const memberStats = useMemo(() => {
    const studentMembers = group.members.filter(m => m.role === Role.Student);
    return studentMembers.map(member => {
        const memberTasks = tasks.filter(t => t.assigneeId === member.id && t.projectId === project.id);
        const totalAssigned = memberTasks.length;

        const difficultyCounts = {
            [Difficulty.Level1]: 0,
            [Difficulty.Level2]: 0,
            [Difficulty.Level3]: 0,
        };

        memberTasks.forEach(task => {
            if (task.difficulty === Difficulty.Level1) {
                difficultyCounts[Difficulty.Level1]++;
