const CountdownDisplay: React.FC<{ endDate: string }> = ({ endDate }) => {
    const timeLeft = useMemo(() => {
        const difference = +new Date(endDate) - +new Date();
        if (difference <= 0) {
            return { overdue: true, weeks: 0, days: 0 };
        }
        const totalDays = Math.ceil(difference / (1000 * 60 * 60 * 24));
        const weeks = Math.floor(totalDays / 7);
        const days = totalDays % 7;
        return { overdue: false, weeks, days };
    }, [endDate]);

    if (timeLeft.overdue) {
        return (
            <div className="text-center">
                <p className="text-sm font-medium text-gray-500">Estado</p>
                <p className="text-base font-bold text-red-600">Finalizado</p>
            </div>
        );
    }
    return (
        <div className="text-center">
             <p className="text-sm font-medium text-gray-500">Tiempo restante para finalizar</p>
             <p className="text-base font-bold text-yellow-600">{`${timeLeft.weeks}sem ${timeLeft.days}d`}</p>
        </div>
    );
};

const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 64 }) => {
    const strokeWidth = 8;

    if (progress === 100) {
        return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-green-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    if (progress === 0) {
         return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-red-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    const radius = size / 2 - strokeWidth / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    const progressColorClass = useMemo(() => {
        if (progress <= 40) return 'text-red-500';
        if (progress <= 79) return 'text-yellow-500';
        return 'text-green-500';
    }, [progress]);

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg className="absolute" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                <circle className="text-gray-200" strokeWidth={strokeWidth} stroke="currentColor" fill="transparent" r={radius} cx={size/2} cy={size/2} />
                <circle
                    className={progressColorClass}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size/2}
                    cy={size/2}
                    style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    transform={`rotate(-90 ${size/2} ${size/2})`}
                />
            </svg>
            <span className="text-base font-bold text-gray-700">{progress}%</span>
        </div>
    );
};

const AdminTutorGroupCard: React.FC<{ group: Group, project?: Project, tasks: Task[], allUsers: User[], onNavigateToKanban: (id: string) => void }> = ({ group, project, tasks, allUsers, onNavigateToKanban }) => {
    const { progress, totalTasks, inProgressTasks, completedTasks } = useMemo(() => {
        if (!project) return { progress: 0, totalTasks: 0, inProgressTasks: 0, completedTasks: 0 };
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const progressPercentage = total > 0 ? Math.round((completed / total) * 100) : 0;
        return { progress: progressPercentage, totalTasks: total, inProgressTasks: inProgress, completedTasks: completed };
    }, [project, tasks]);

    const tutor = allUsers.find(u => u.id === group.tutorId);

    const courseGroup = useMemo(() => {
        if (group.members.length > 0) {
            for (const member of group.members) {
                const freshMemberInfo = allUsers.find(u => u.id === member.id);
                if (freshMemberInfo && freshMemberInfo.courseGroup) {
                    return freshMemberInfo.courseGroup;
                }
            }
        }
        return 'Curso no definido';
    }, [group.members, allUsers]);

    return (
        <div onClick={() => project && onNavigateToKanban(project.id)} className="flex flex-col p-6 bg-white rounded-lg shadow-md transition-shadow duration-200 hover:shadow-lg cursor-pointer">
            <div className="flex items-start gap-4">
                <div className="flex-shrink-0"><ProgressCircle progress={progress} /></div>
                <div className="flex-1">
                    <h3 className="text-lg font-bold text-green-700">{project ? project.name : group.name}</h3>
                    <p className="text-sm text-gray-500">{project ? group.name : 'Grupo sin proyecto'}</p>
                    <p className="mt-1 text-sm font-semibold text-gray-600">{courseGroup}</p>
                    {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                </div>
            </div>
            <div className="flex justify-around pt-4 mt-4 border-t border-gray-200">
                <div className="text-center"><p className="text-xl font-bold text-gray-800">{totalTasks}</p><p className="text-xs font-medium text-gray-500">Totales</p></div>
                <div className="text-center"><p className="text-xl font-bold text-blue-600">{inProgressTasks}</p><p className="text-xs font-medium text-gray-500">En Curso</p></div>
                <div className="text-center"><p className="text-xl font-bold text-green-600">{completedTasks}</p><p className="text-xs font-medium text-gray-500">Completadas</p></div>
            </div>
             {project?.startDate && project?.endDate && (
                <div className="grid grid-cols-3 gap-2 pt-4 mt-4 border-t border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-bold text-gray-800">{new Date(project.startDate).toLocaleDateString()}</p>
                        <p className="text-xs font-medium text-gray-500">Inicio</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-bold text-gray-800">{new Date(project.endDate).toLocaleDateString()}</p>
                        <p className="text-xs font-medium text-gray-500">Fin</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>
            )}
        </div>
    );
};

