                if (freshMemberInfo && freshMemberInfo.courseGroup) {
                    return freshMemberInfo.courseGroup;
                }
            }
        }
        return 'Curso no definido';
    }, [group.members, allUsers]);

    return (
        <div onClick={() => project && onNavigateToKanban(project.id)} className="flex flex-col p-6 bg-white rounded-lg shadow-md transition-shadow duration-200 hover:shadow-lg cursor-pointer">
