const StudentProjectDetailCard: React.FC<{
    group: Group;
    project: Project;
    tasks: Task[];
    tutorials: Tutorial[];
    allUsers: User[];
    user: User;
    onNavigateToKanban: (projectId: string) => void;
}> = ({ group, project, tasks, tutorials, allUsers, user, onNavigateToKanban }) => {
    const { progress, totalTasks, pendingTasks, inProgressTasks, completedTasks } = useMemo(() => {
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const pending = groupTasks.filter(t => t.status === KanbanStatus.Backlog).length;
        return {
            progress: total > 0 ? Math.round((completed / total) * 100) : 0,
            totalTasks: total,
            pendingTasks: pending,
            inProgressTasks: inProgress,
            completedTasks: completed,
        };
    }, [project, tasks]);

    const tutor = useMemo(() => allUsers.find(u => u.id === group.tutorId), [allUsers, group.tutorId]);

    const { pastTutorialsCount, nextTutorialDate } = useMemo(() => {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const groupTutorials = tutorials.filter(t => t.groupId === group.id);
        const pastTutorials = groupTutorials.filter(t => new Date(t.date + 'T00:00:00') < today);
        const futureTutorials = groupTutorials
            .filter(t => t.nextDate && new Date(t.nextDate + 'T00:00:00') >= today)
            .sort((a, b) => new Date(a.nextDate).getTime() - new Date(b.nextDate).getTime());

        const nextDateInfo = futureTutorials.length > 0
            ? `${new Date(futureTutorials[0].nextDate + 'T00:00:00').toLocaleDateString('es-ES')} ${futureTutorials[0].nextTime ? `a las ${futureTutorials[0].nextTime}`: ''}`
            : 'No agendada';

        return { pastTutorialsCount: pastTutorials.length, nextTutorialDate: nextDateInfo };
    }, [tutorials, group.id]);

    const groupMeetingsCount = 0; // Placeholder
    const nextGroupMeetingDate = "No agendada"; // Placeholder

    const memberStats = useMemo(() => {
        // 1. Initialize stats for each student member of the group
        const stats = new Map<string, { name: string; completed: number; inProgress: number; pending: number; }>();
        group.members.forEach(member => {
            if (member.role === Role.Student) {
                stats.set(member.id, {
                    name: member.name,
                    completed: 0,
                    inProgress: 0,
                    pending: 0,
                });
            }
        });

        // 2. Filter tasks for the current project
        const projectTasks = tasks.filter(task => task.projectId === project.id);

        // 3. Iterate over the project's tasks and increment counters for the assigned student
        projectTasks.forEach(task => {
            if (task.assigneeId && stats.has(task.assigneeId)) {
                const memberStat = stats.get(task.assigneeId)!;
                switch (task.status) {
                    case KanbanStatus.Done:
                        memberStat.completed++;
                        break;
                    case KanbanStatus.Doing:
                        memberStat.inProgress++;
                        break;
                    case KanbanStatus.Backlog:
                        memberStat.pending++;
                        break;
                }
            }
        });

        // 4. Convert map to array and calculate total
        const result = Array.from(stats.entries()).map(([id, statData]) => {
            const totalAssigned = statData.completed + statData.inProgress + statData.pending;
            return {
                id,
                name: statData.name,
                completed: statData.completed,
                inProgress: statData.inProgress,
                pending: statData.pending,
                totalAssigned,
            };
        });

        // 5. Sort and return
        return result.sort((a, b) => b.totalAssigned - a.totalAssigned);
    }, [group.members, tasks, project.id]);

    return (
        <div className="w-full p-6 bg-white rounded-lg shadow-md">
            <div onClick={() => onNavigateToKanban(project.id)} className="cursor-pointer">
                <div className="flex flex-col sm:flex-row items-stretch gap-6">
                    <div className="flex-shrink-0 flex items-center justify-center">
                        <ProgressCircle progress={progress} size={96} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-xl font-bold text-green-700">{project.name}</h3>
                        <p className="text-base text-gray-500">{user.courseGroup} - {group.name}</p>
                        {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                        <div className="pt-2 mt-2 border-t border-gray-200">
                            <h4 className="mb-1 text-sm font-semibold text-gray-600">Componentes del Grupo:</h4>
                            <div className="flex flex-wrap gap-x-4 gap-y-1">
                                {group.members
                                    .filter(member => member.role === Role.Student)
                                    .map(member => (
                                    <span key={member.id} className="text-sm text-gray-800">{member.name}</span>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 pt-4 mt-4 border-t border-gray-200">
                    <div className="p-4 text-center bg-gray-50 rounded-lg border border-gray-200">
                        <p className="text-2xl font-bold text-gray-800">{totalTasks}</p>
                        <p className="text-sm font-medium text-gray-500">Tareas Totales</p>
                    </div>
                    <div className="p-4 text-center bg-gray-50 rounded-lg border border-gray-200">
                        <p className="text-2xl font-bold text-red-600">{pendingTasks}</p>
                        <p className="text-sm font-medium text-gray-500">Pendientes</p>
                    </div>
                    <div className="p-4 text-center bg-gray-50 rounded-lg border border-gray-200">
                        <p className="text-2xl font-bold text-blue-600">{inProgressTasks}</p>
                        <p className="text-sm font-medium text-gray-500">En Curso</p>
                    </div>
                    <div className="p-4 text-center bg-gray-50 rounded-lg border border-gray-200">
                        <p className="text-2xl font-bold text-green-600">{completedTasks}</p>
                        <p className="text-sm font-medium text-gray-500">Completadas</p>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2 pt-4 mt-4 border-t md:grid-cols-3 border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Inicio de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.startDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Fin de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.endDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>

                <div className="pt-4 mt-4 border-t border-gray-200">
                    <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
                        <div className="p-3 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Reuniones de Grupo</p>
                            <p className="text-2xl font-bold text-blue-600">{groupMeetingsCount}</p>
                        </div>
                        <div className="p-3 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Reunión Grupo</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextGroupMeetingDate}</p>
                        </div>
                        <div className="p-3 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Tutorías Realizadas</p>
                            <p className="text-2xl font-bold text-blue-600">{pastTutorialsCount}</p>
                        </div>
                        <div className="p-3 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Tutoría</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextTutorialDate}</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="pt-4 mt-4 border-t border-gray-200">
                <h4 className="mb-4 text-lg font-bold text-gray-700">Rendimiento del Grupo por Tareas</h4>

                {/* Header Row */}
                <div className="flex justify-end mb-2 pr-2">
                    <div className="flex gap-6">
                        <div className="w-20 text-center text-xs font-bold text-gray-500">Total</div>
                        <div className="w-20 text-center text-xs font-bold text-red-600">Pendiente</div>
                        <div className="w-20 text-center text-xs font-bold text-blue-600">En Progreso</div>
                        <div className="w-20 text-center text-xs font-bold text-green-600">Realizadas</div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2">
                    {memberStats.map(stat => (
                        <div key={stat.id} className="flex items-center justify-between p-2 bg-gray-50 rounded-lg border border-gray-200">
                            <span className="font-medium text-gray-800">{stat.name}</span>
                            <div className="flex items-center gap-6">
                                <div className="flex justify-center w-20">
                                    <span title="Total de Tareas" className="flex items-center justify-center w-7 h-7 text-xs font-bold text-white bg-black rounded-full">
                                        {stat.totalAssigned}
                                    </span>
                                </div>
                                <div className="flex justify-center w-20">
                                    <span title="Tareas Pendientes" className="flex items-center justify-center w-7 h-7 text-xs font-bold text-white bg-red-500 rounded-full">
                                        {stat.pending}
                                    </span>
                                </div>
                                <div className="flex justify-center w-20">
                                    <span title="Tareas En Progreso" className="flex items-center justify-center w-7 h-7 text-xs font-bold text-white bg-blue-600 rounded-full">
                                        {stat.inProgress}
                                    </span>
                                </div>
                                <div className="flex justify-center w-20">
                                    <span title="Tareas Terminadas" className="flex items-center justify-center w-7 h-7 text-xs font-bold text-white bg-green-600 rounded-full">
                                        {stat.completed}
                                    </span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};


const StudentDashboard: React.FC<{
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    tutorials: Tutorial[];
    allUsers: User[];
    onNavigateToKanban: (projectId: string) => void;
}> = ({ user, groups, projects, tasks, tutorials, allUsers, onNavigateToKanban }) => {

    const userProjectsWithGroups = useMemo(() => {
        return projects
            .filter(p => user.groupIds.includes(p.groupId))
            .map(project => ({
                project,
                group: groups.find(g => g.id === project.groupId)
            }))
            .filter((item): item is { project: Project; group: Group } => !!item.group);
    }, [user, projects, groups]);

    if (userProjectsWithGroups.length === 0) {
        return (
            <div className="p-6 text-center text-gray-500 bg-white rounded-lg shadow-md">
                <p>Actualmente no estás asignado a ningún proyecto.</p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {userProjectsWithGroups.map(({ project, group }) => (
                <StudentProjectDetailCard
                    key={project.id}
                    group={group}
                    project={project}
                    tasks={tasks}
                    tutorials={tutorials}
                    allUsers={allUsers}
                    user={user}
                    onNavigateToKanban={onNavigateToKanban}
                />
            ))}
        </div>
    );
};

const AdminTutorDashboard: React.FC<{ groups: Group[]; projects: Project[]; tasks: Task[]; allUsers: User[]; onNavigateToKanban: (projectId: string) => void; }> = ({ groups, projects, tasks, allUsers, onNavigateToKanban }) => {
    const [expandedCourseGroups, setExpandedCourseGroups] = useState<Record<string, boolean>>({});

    const projectsByCourseGroup = useMemo(() => {
        const result: Record<string, { project: Project, group: Group }[]> = {};

        projects.forEach(project => {
            const group = groups.find(g => g.id === project.groupId);
            if (group && group.members.length > 0) {
                let projectCourseGroup: string | undefined;
                for (const member of group.members) {
                    const freshMember = allUsers.find(u => u.id === member.id);
                    if (freshMember && freshMember.courseGroup) {
                        projectCourseGroup = freshMember.courseGroup;
                        break;
                    }
                }

                if (projectCourseGroup) {
                    if (!result[projectCourseGroup]) {
                        result[projectCourseGroup] = [];
                    }
                    result[projectCourseGroup].push({ project, group });
                }
            }
        });
        return result;
    }, [projects, groups, allUsers]);

    const toggleCourseGroup = (courseGroupName: string) => {
        setExpandedCourseGroups(prev => ({ ...prev, [courseGroupName]: !prev[courseGroupName] }));
    };

    return (
        <div className="space-y-4">
            {Object.keys(projectsByCourseGroup).sort().map(courseGroup => {
                const projectsData = projectsByCourseGroup[courseGroup];
                const isExpanded = !!expandedCourseGroups[courseGroup];
                return (
                    <div key={courseGroup} className="bg-white rounded-lg shadow-md">
                        <button onClick={() => toggleCourseGroup(courseGroup)} className="flex items-center justify-between w-full p-4 text-left focus:outline-none">
                            <div className="flex items-center">
                                <h3 className="text-lg font-semibold text-gray-800">{courseGroup}</h3>
                                <span className="ml-4 px-3 py-1 text-sm font-semibold text-green-800 bg-green-100 rounded-full">{projectsData.length} {projectsData.length === 1 ? 'proyecto' : 'proyectos'}</span>
                            </div>
                            <ChevronDownIcon className={`w-6 h-6 text-gray-500 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </button>
                        {isExpanded && (
                            <div className="p-4 border-t border-gray-200">
                                <div className="grid grid-cols-1 gap-6 md:grid-cols-2 xl:grid-cols-3">
                                    {projectsData.map(({ project, group }) => (
                                        <AdminTutorGroupCard
                                            key={project.id}
                                            group={group}
                                            project={project}
                                            tasks={tasks}
                                            allUsers={allUsers}
                                            onNavigateToKanban={onNavigateToKanban}
                                        />
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
};

const Dashboard: React.FC<DashboardProps> = ({ user, groups, projects, tasks, allUsers, messages, tutorials, onNavigateToKanban, onSendMessage, onMarkMessagesAsRead }) => {
    const [isPendingModalOpen, setIsPendingModalOpen] = useState(false);

    const unreadMessages = useMemo(() => messages.filter(msg => 
        msg.recipientIds.includes(user.id) && !msg.readBy.includes(user.id)
    ), [messages, user.id]);

    const handleClosePendingModal = () => {
        setIsPendingModalOpen(false);
    };

    const { visibleGroups, visibleProjects } = useMemo(() => {
        if (user.role === Role.Admin) {
            return { visibleGroups: groups, visibleProjects: projects };
        }
        if (user.role === Role.Tutor) {
            const tutorGroups = groups.filter(g => g.tutorId === user.id);
            const tutorGroupIds = tutorGroups.map(g => g.id);
            const tutorProjects = projects.filter(p => tutorGroupIds.includes(p.groupId));
            return { visibleGroups: tutorGroups, visibleProjects: tutorProjects };
        }
        return { visibleGroups: [], visibleProjects: [] };
    }, [user, groups, projects]);

    return (
        <div>
            <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <h2 className="text-2xl font-bold text-gray-800">
                    {user.role === Role.Student ? 'Mis Proyectos' : 'Proyectos por Curso'}
                </h2>
                <button
                    onClick={() => unreadMessages.length > 0 && setIsPendingModalOpen(true)}
                    className={`px-4 py-2 font-bold rounded-md transition-all ${
                        unreadMessages.length > 0
                            ? 'bg-red-500 text-white blinking-button shadow-lg hover:bg-red-600'
                            : 'bg-green-500 text-white cursor-default'
                    }`}
                >
                    {unreadMessages.length > 0 ? `Mensajes Pendientes (${unreadMessages.length})` : 'Sin Mensajes Pendientes'}
                </button>
            </div>

            {(user.role === Role.Admin || user.role === Role.Tutor)
                ? <AdminTutorDashboard 
                    groups={visibleGroups} 
                    projects={visibleProjects} 
                    tasks={tasks} 
                    allUsers={allUsers} 
                    onNavigateToKanban={onNavigateToKanban} 
                  /> 
                : <StudentDashboard 
                    user={user} 
                    groups={groups} 
                    projects={projects} 
                    tasks={tasks} 
                    tutorials={tutorials}
                    allUsers={allUsers}
                    onNavigateToKanban={onNavigateToKanban} 
                  />}

            {isPendingModalOpen && (
                <PendingMessagesModal
                    user={user}
                    messages={unreadMessages}
                    allUsers={allUsers}
                    onClose={handleClosePendingModal}
                    onSendMessage={onSendMessage}
                    onMarkMessagesAsRead={onMarkMessagesAsRead}
                />
            )}
        </div>
    );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { User, Task, Role, KanbanStatus, Group, Project, Message, Tutorial, Priority, Difficulty } from '../types';
import { ChevronDownIcon } from './Icons';
import PendingMessagesModal from './PendingMessagesModal';

interface DashboardProps {
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    allUsers: User[];
    messages: Message[];
    tutorials: Tutorial[];
    onNavigateToKanban: (projectId: string) => void;
    onSendMessage: (messageData: any) => void;
    onMarkMessagesAsRead: (messageIds: string[]) => void;
}

// --- Componentes para la vista de Administrador y Tutor ---

const CountdownDisplay: React.FC<{ endDate: string }> = ({ endDate }) => {
    const timeLeft = useMemo(() => {
        const difference = +new Date(endDate) - +new Date();
        if (difference <= 0) {
            return { overdue: true, weeks: 0, days: 0 };
        }
        const totalDays = Math.ceil(difference / (1000 * 60 * 60 * 24));
        const weeks = Math.floor(totalDays / 7);
        const days = totalDays % 7;
        return { overdue: false, weeks, days };
    }, [endDate]);

    if (timeLeft.overdue) {
        return (
            <div className="text-center">
                <p className="text-sm font-medium text-gray-500">Estado</p>
                <p className="text-base font-bold text-red-600">Finalizado</p>
            </div>
        );
    }
    return (
        <div className="text-center">
             <p className="text-sm font-medium text-gray-500">Tiempo restante para finalizar</p>
             <p className="text-base font-bold text-yellow-600">{`${timeLeft.weeks}sem ${timeLeft.days}d`}</p>
        </div>
    );
};

const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 64 }) => {
    const strokeWidth = 8;

    if (progress === 100) {
        return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-green-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    if (progress === 0) {
         return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-red-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    const radius = size / 2 - strokeWidth / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    const progressColorClass = useMemo(() => {
        if (progress <= 40) return 'text-red-500';
        if (progress <= 79) return 'text-yellow-500';
        return 'text-green-500';
    }, [progress]);

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg className="absolute" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                <circle className="text-gray-200" strokeWidth={strokeWidth} stroke="currentColor" fill="transparent" r={radius} cx={size/2} cy={size/2} />
                <circle
                    className={progressColorClass}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size/2}
                    cy={size/2}
                    style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    transform={`rotate(-90 ${size/2} ${size/2})`}
                />
            </svg>
            <span className="text-base font-bold text-gray-700">{progress}%</span>
        </div>
    );
};

const AdminTutorGroupCard: React.FC<{ group: Group, project?: Project, tasks: Task[], allUsers: User[], onNavigateToKanban: (id: string) => void }> = ({ group, project, tasks, allUsers, onNavigateToKanban }) => {
    const { progress, totalTasks, inProgressTasks, completedTasks } = useMemo(() => {
        if (!project) return { progress: 0, totalTasks: 0, inProgressTasks: 0, completedTasks: 0 };
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const progressPercentage = total > 0 ? Math.round((completed / total) * 100) : 0;
        return { progress: progressPercentage, totalTasks: total, inProgressTasks: inProgress, completedTasks: completed };
    }, [project, tasks]);

    const tutor = allUsers.find(u => u.id === group.tutorId);

    const courseGroup = useMemo(() => {
        if (group.members.length > 0) {
            for (const member of group.members) {
                const freshMemberInfo = allUsers.find(u => u.id === member.id);
                if (freshMemberInfo && freshMemberInfo.courseGroup) {
                    return freshMemberInfo.courseGroup;
                }
            }
        }
        return 'Curso no definido';
    }, [group.members, allUsers]);

    return (
        <div onClick={() => project && onNavigateToKanban(project.id)} className="flex flex-col p-6 bg-white rounded-lg shadow-md transition-shadow duration-200 hover:shadow-lg cursor-pointer">
            <div className="flex items-start gap-4">
                <div className="flex-shrink-0"><ProgressCircle progress={progress} /></div>
                <div className="flex-1">
                    <h3 className="text-lg font-bold text-green-700">{project ? project.name : group.name}</h3>
                    <p className="text-sm text-gray-500">{project ? group.name : 'Grupo sin proyecto'}</p>
                    <p className="mt-1 text-sm font-semibold text-gray-600">{courseGroup}</p>
                    {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                </div>
            </div>
            <div className="flex justify-around pt-4 mt-4 border-t border-gray-200">
                <div className="text-center"><p className="text-xl font-bold text-gray-800">{totalTasks}</p><p className="text-xs font-medium text-gray-500">Totales</p></div>
                <div className="text-center"><p className="text-xl font-bold text-blue-600">{inProgressTasks}</p><p className="text-xs font-medium text-gray-500">En Curso</p></div>
                <div className="text-center"><p className="text-xl font-bold text-green-600">{completedTasks}</p><p className="text-xs font-medium text-gray-500">Completadas</p></div>
            </div>
             {project?.startDate && project?.endDate && (
                <div className="grid grid-cols-3 gap-2 pt-4 mt-4 border-t border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-bold text-gray-800">{new Date(project.startDate).toLocaleDateString()}</p>
                        <p className="text-xs font-medium text-gray-500">Inicio</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-bold text-gray-800">{new Date(project.endDate).toLocaleDateString()}</p>
                        <p className="text-xs font-medium text-gray-500">Fin</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>
            )}
        </div>
    );
};

