const CountdownDisplay: React.FC<{ endDate: string }> = ({ endDate }) => {
    const timeLeft = useMemo(() => {
        const difference = +new Date(endDate) - +new Date();
        if (difference <= 0) {
            return { overdue: true, weeks: 0, days: 0 };
        }
        const totalDays = Math.ceil(difference / (1000 * 60 * 60 * 24));
        const weeks = Math.floor(totalDays / 7);
        const days = totalDays % 7;
        return { overdue: false, weeks, days };
    }, [endDate]);

    if (timeLeft.overdue) {
        return (
            <div className="text-center">
                <p className="text-sm font-medium text-gray-500">Estado</p>
                <p className="text-base font-bold text-red-600">Finalizado</p>
            </div>
        );
    }

    const weeksText = timeLeft.weeks === 1 ? 'semana' : 'semanas';
    const daysText = timeLeft.days === 1 ? 'día' : 'días';

    return (
        <div className="text-center">
             <p className="text-sm font-medium text-gray-500">Tiempo restante para finalizar</p>
             <p className="text-base font-bold text-yellow-600">{`${timeLeft.weeks} ${weeksText} + ${timeLeft.days} ${daysText}`}</p>
        </div>
    );
};

const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 64 }) => {
    const strokeWidth = 8;

    if (progress === 100) {
        return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-green-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    if (progress === 0) {
         return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-red-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-base font-bold text-white">{progress}%</span>
            </div>
        );
    }

    const radius = size / 2 - strokeWidth / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    const progressColorClass = useMemo(() => {
        if (progress <= 40) return 'text-red-500';
        if (progress <= 79) return 'text-yellow-500';
        return 'text-green-500';
    }, [progress]);

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg className="absolute" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                <circle className="text-gray-200" strokeWidth={strokeWidth} stroke="currentColor" fill="transparent" r={radius} cx={size/2} cy={size/2} />
                <circle
                    className={progressColorClass}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size/2}
                    cy={size/2}
                    style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    transform={`rotate(-90 ${size/2} ${size/2})`}
                />
            </svg>
            <span className="text-base font-bold text-gray-700">{progress}%</span>
        </div>
    );
};

const AdminTutorGroupCard: React.FC<{ 
    group: Group; 
    project: Project; 
    tasks: Task[]; 
    allUsers: User[]; 
    tutorials: Tutorial[];
    onNavigateToKanban: (id: string) => void;
}> = ({ group, project, tasks, allUsers, tutorials, onNavigateToKanban }) => {
    const { progress, totalTasks, pendingTasks, inProgressTasks, completedTasks } = useMemo(() => {
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const pending = groupTasks.filter(t => t.status === KanbanStatus.Backlog).length;
        return {
            progress: total > 0 ? Math.round((completed / total) * 100) : 0,
            totalTasks: total,
            pendingTasks: pending,
            inProgressTasks: inProgress,
            completedTasks: completed,
        };
    }, [project, tasks]);

    const tutor = useMemo(() => allUsers.find(u => u.id === group.tutorId), [allUsers, group.tutorId]);

    const courseGroup = useMemo(() => {
        if (group.members.length > 0) {
            for (const member of group.members) {
                const freshMemberInfo = allUsers.find(u => u.id === member.id);
                if (freshMemberInfo && freshMemberInfo.courseGroup) {
                    return freshMemberInfo.courseGroup;
                }
            }
        }
        return 'Curso no definido';
    }, [group.members, allUsers]);

    const { pastTutorialsCount, nextTutorialDate } = useMemo(() => {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const groupTutorials = tutorials.filter(t => t.groupId === group.id);
        const pastTutorials = groupTutorials.filter(t => new Date(t.date + 'T00:00:00') < today);
        const futureTutorials = groupTutorials
            .filter(t => t.nextDate && new Date(t.nextDate + 'T00:00:00') >= today)
            .sort((a, b) => new Date(a.nextDate).getTime() - new Date(b.nextDate).getTime());

        const nextDateInfo = futureTutorials.length > 0
            ? `${new Date(futureTutorials[0].nextDate + 'T00:00:00').toLocaleDateString('es-ES')} ${futureTutorials[0].nextTime ? `a las ${futureTutorials[0].nextTime}`: ''}`
            : 'No agendada';

        return { pastTutorialsCount: pastTutorials.length, nextTutorialDate: nextDateInfo };
    }, [tutorials, group.id]);

    const groupMeetingsCount = 0; // Placeholder
    const nextGroupMeetingDate = "No agendada"; // Placeholder

    const calculateTaskStats = (tasks: Task[]) => {
        const stats = {
            tasks,
            count: tasks.length,
            byDifficulty: {
                [Difficulty.Level1]: 0,
                [Difficulty.Level2]: 0,
                [Difficulty.Level3]: 0,
            }
        };
        tasks.forEach(task => {
            if (stats.byDifficulty[task.difficulty] !== undefined) {
                stats.byDifficulty[task.difficulty]++;
            }
        });
        return stats;
    };

    const memberStats = useMemo(() => {
        const statsMap = new Map<string, { name: string; completed: Task[]; inProgress: Task[]; pending: Task[]; }>();
        group.members.forEach(member => {
            if (member.role === Role.Student) {
                statsMap.set(member.id, {
                    name: member.name,
                    completed: [],
                    inProgress: [],
                    pending: [],
                });
            }
        });

        const projectTasks = tasks.filter(task => task.projectId === project.id);

        projectTasks.forEach(task => {
            if (task.assigneeId && statsMap.has(task.assigneeId)) {
                const memberStat = statsMap.get(task.assigneeId)!;
                switch (task.status) {
                    case KanbanStatus.Done:
                        memberStat.completed.push(task);
                        break;
                    case KanbanStatus.Doing:
                        memberStat.inProgress.push(task);
                        break;
                    case KanbanStatus.Backlog:
                        memberStat.pending.push(task);
                        break;
                }
            }
        });

        const result = Array.from(statsMap.entries()).map(([id, statData]) => {
            const pendingStats = calculateTaskStats(statData.pending);
            const inProgressStats = calculateTaskStats(statData.inProgress);
            const completedStats = calculateTaskStats(statData.completed);
            const allTasks = [...statData.pending, ...statData.inProgress, ...statData.completed];
            const totalStats = calculateTaskStats(allTasks);

            return {
                id,
                name: statData.name,
                completed: completedStats,
                inProgress: inProgressStats,
                pending: pendingStats,
                totalAssigned: totalStats,
            };
        });

        return result.sort((a, b) => b.totalAssigned.count - a.totalAssigned.count);
    }, [group.members, tasks, project.id]);

    const difficultyConfig: { [key in Difficulty]: { bg: string, text: string, name: string } } = {
        [Difficulty.Level1]: { bg: 'bg-green-200', text: 'text-green-800', name: 'Sencilla' },
        [Difficulty.Level2]: { bg: 'bg-yellow-200', text: 'text-yellow-800', name: 'Moderada' },
        [Difficulty.Level3]: { bg: 'bg-red-200', text: 'text-red-800', name: 'Compleja' },
    };

    return (
        <div className="w-full p-4 bg-white rounded-lg shadow-md">
            <div onClick={() => onNavigateToKanban(project.id)} className="cursor-pointer">
                <div className="flex flex-col sm:flex-row items-stretch gap-6">
                    <div className="flex-shrink-0 flex items-center justify-center">
                        <ProgressCircle progress={progress} size={96} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-xl font-bold text-green-700">{project.name}</h3>
                        <p className="text-base text-gray-500">{courseGroup} - {group.name}</p>
                        {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                        <div className="pt-2 mt-2 border-t border-gray-200">
                            <h4 className="mb-1 text-sm font-semibold text-gray-600">Componentes del Grupo:</h4>
                            <div className="flex flex-wrap gap-x-4 gap-y-1">
                                {group.members
                                    .filter(member => member.role === Role.Student)
                                    .map(member => (
                                    <span key={member.id} className="text-sm text-gray-800">{member.name}</span>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2 pt-3 mt-3 border-t md:grid-cols-3 border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Inicio de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.startDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Fin de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.endDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>

                <div className="pt-3 mt-3 border-t border-gray-200">
                    <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Reuniones de Grupo</p>
                            <p className="text-2xl font-bold text-blue-600">{groupMeetingsCount}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Reunión Grupo</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextGroupMeetingDate}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Tutorías Realizadas</p>
