                        <div className="flex-1 text-center text-xs font-bold text-gray-500">Total</div>
                        <div className="flex-1 text-center text-xs font-bold text-red-600">Pendientes</div>
                        <div className="flex-1 text-center text-xs font-bold text-blue-600">En Progreso</div>
                        <div className="flex-1 text-center text-xs font-bold text-green-600">Realizadas</div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2">
                    {memberStats.map(stat => {
                        const name = stat.name;
                        const firstSpaceIndex = name.indexOf(' ');
                        const firstName = firstSpaceIndex === -1 ? name : name.substring(0, firstSpaceIndex);
                        const lastName = firstSpaceIndex === -1 ? '' : name.substring(firstSpaceIndex + 1);

                        return (
                            <div key={stat.id} className="flex items-center justify-between p-2 bg-gray-50 rounded-lg border border-gray-200">
                                <div className="w-1/3 text-left" title={stat.name}>
                                    <p className="font-medium text-gray-800 truncate">{firstName}</p>
                                    {lastName && <p className="text-sm text-gray-600 truncate">{lastName}</p>}
                                </div>
                                <div className="flex justify-around w-2/3">
                                    <StatusColumn title="Total de Tareas" mainCircleClass="bg-black" stats={stat.totalAssigned} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Pendientes" mainCircleClass="bg-red-500" stats={stat.pending} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas En Progreso" mainCircleClass="bg-blue-600" stats={stat.inProgress} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Realizadas" mainCircleClass="bg-green-600" stats={stat.completed} difficultyConfig={difficultyConfig} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};


const StudentDashboard: React.FC<{
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    tutorials: Tutorial[];
    allUsers: User[];
    onNavigateToKanban: (projectId: string) => void;
}> = ({ user, groups, projects, tasks, tutorials, allUsers, onNavigateToKanban }) => {

    const userProjectsWithGroups = useMemo(() => {
        return projects
            .filter(p => user.groupIds.includes(p.groupId))
            .map(project => ({
                project,
                group: groups.find(g => g.id === project.groupId)
            }))
            .filter((item): item is { project: Project; group: Group } => !!item.group);
    }, [user, projects, groups]);

    if (userProjectsWithGroups.length === 0) {
        return (
            <div className="p-6 text-center text-gray-500 bg-white rounded-lg shadow-md">
                <p>Actualmente no estás asignado a ningún proyecto.</p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {userProjectsWithGroups.map(({ project, group }) => (
                <StudentProjectDetailCard
                    key={project.id}
                    group={group}
                    project={project}
                    tasks={tasks}
                    tutorials={tutorials}
                    allUsers={allUsers}
                    user={user}
                    onNavigateToKanban={onNavigateToKanban}
                />
            ))}
        </div>
    );
};

const AdminTutorDashboard: React.FC<{ 
    groups: Group[]; 
    projects: Project[]; 
    tasks: Task[]; 
    allUsers: User[]; 
    tutorials: Tutorial[];
    onNavigateToKanban: (projectId: string) => void; 
}> = ({ groups, projects, tasks, allUsers, tutorials, onNavigateToKanban }) => {
    const [expandedCourseGroups, setExpandedCourseGroups] = useState<Record<string, boolean>>({});

    const projectsByCourseGroup = useMemo(() => {
        const result: Record<string, { project: Project, group: Group }[]> = {};

        projects.forEach(project => {
            const group = groups.find(g => g.id === project.groupId);
            if (group && group.members.length > 0) {
                let projectCourseGroup: string | undefined;
                for (const member of group.members) {
                    const freshMember = allUsers.find(u => u.id === member.id);
                    if (freshMember && freshMember.courseGroup) {
                        projectCourseGroup = freshMember.courseGroup;
                        break;
                    }
                }

                if (projectCourseGroup) {
                    if (!result[projectCourseGroup]) {
                        result[projectCourseGroup] = [];
                    }
                    result[projectCourseGroup].push({ project, group });
                }
            }
        });
        return result;
    }, [projects, groups, allUsers]);

    const toggleCourseGroup = (courseGroupName: string) => {
        setExpandedCourseGroups(prev => ({ ...prev, [courseGroupName]: !prev[courseGroupName] }));
    };

    return (
        <div className="space-y-4">
            {Object.keys(projectsByCourseGroup).sort().map(courseGroup => {
                const projectsData = projectsByCourseGroup[courseGroup];
                const isExpanded = !!expandedCourseGroups[courseGroup];
                return (
                    <div key={courseGroup} className="bg-white rounded-lg shadow-md">
                        <button onClick={() => toggleCourseGroup(courseGroup)} className="flex items-center justify-between w-full p-4 text-left focus:outline-none">
                            <div className="flex items-center">
                                <h3 className="text-lg font-semibold text-gray-800">{courseGroup}</h3>
                                <span className="ml-4 px-3 py-1 text-sm font-semibold text-green-800 bg-green-100 rounded-full">{projectsData.length} {projectsData.length === 1 ? 'proyecto' : 'proyectos'}</span>
                            </div>
                            <ChevronDownIcon className={`w-6 h-6 text-gray-500 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </button>
                        {isExpanded && (
                            <div className="p-4 border-t border-gray-200">
                                <div className="grid grid-cols-1 gap-6">
                                    {projectsData.map(({ project, group }) => (
                                        <AdminTutorGroupCard
                                            key={project.id}
                                            group={group}
                                            project={project}
                                            tasks={tasks}
                                            allUsers={allUsers}
                                            tutorials={tutorials}
                                            onNavigateToKanban={onNavigateToKanban}
                                        />
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
};

const Dashboard: React.FC<DashboardProps> = ({ user, groups, projects, tasks, allUsers, messages, tutorials, onNavigateToKanban, onSendMessage, onMarkMessagesAsRead }) => {
    const [isPendingModalOpen, setIsPendingModalOpen] = useState(false);

    const unreadMessages = useMemo(() => messages.filter(msg => 
        msg.recipientIds.includes(user.id) && !msg.readBy.includes(user.id)
    ), [messages, user.id]);

    const handleClosePendingModal = () => {
        setIsPendingModalOpen(false);
    };

    const { visibleGroups, visibleProjects } = useMemo(() => {
        if (user.role === Role.Admin) {
            return { visibleGroups: groups, visibleProjects: projects };
        }
        if (user.role === Role.Tutor) {
            const tutorGroups = groups.filter(g => g.tutorId === user.id);
            const tutorGroupIds = tutorGroups.map(g => g.id);
            const tutorProjects = projects.filter(p => tutorGroupIds.includes(p.groupId));
            return { visibleGroups: tutorGroups, visibleProjects: tutorProjects };
        }
        return { visibleGroups: [], visibleProjects: [] };
    }, [user, groups, projects]);

    return (
        <div>
            <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <h2 className="text-2xl font-bold text-gray-800">
                    {user.role === Role.Student ? 'Mis Proyectos' : 'Proyectos por Curso'}
                </h2>
                <button
                    onClick={() => unreadMessages.length > 0 && setIsPendingModalOpen(true)}
                    className={`px-4 py-2 font-bold rounded-md transition-all ${
                        unreadMessages.length > 0
                            ? 'bg-red-500 text-white blinking-button shadow-lg hover:bg-red-600'
                            : 'bg-green-500 text-white cursor-default'
                    }`}
                >
                    {unreadMessages.length > 0 ? `Mensajes Pendientes (${unreadMessages.length})` : 'Sin Mensajes Pendientes'}
                </button>
            </div>

            {(user.role === Role.Admin || user.role === Role.Tutor)
                ? <AdminTutorDashboard 
                    groups={visibleGroups} 
                    projects={visibleProjects} 
                    tasks={tasks} 
                    allUsers={allUsers} 
                    tutorials={tutorials}
                    onNavigateToKanban={onNavigateToKanban} 
                  /> 
                : <StudentDashboard 
                    user={user} 
                    groups={groups} 
                    projects={projects} 
                    tasks={tasks} 
                    tutorials={tutorials}
                    allUsers={allUsers}
                    onNavigateToKanban={onNavigateToKanban} 
                  />}

            {isPendingModalOpen && (
                <PendingMessagesModal
                    user={user}
                    messages={unreadMessages}
                    allUsers={allUsers}
                    onClose={handleClosePendingModal}
                    onSendMessage={onSendMessage}
                    onMarkMessagesAsRead={onMarkMessagesAsRead}
                />
            )}
        </div>
    );
};

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import { User, Task, KanbanStatus, Role, Group, Project, Priority, RA, Difficulty } from '../types';
import { KANBAN_COLUMNS_ORDER, STATUS_COLORS } from '../constants';
import KanbanCard from './KanbanCard';
import Modal from './Modal';
import { PlusCircleIcon, TrashIcon } from './Icons';

interface KanbanBoardProps {
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    users: User[];
    ras: RA[];
    courseDates: { startDate: string; endDate: string; };
    onCreateTask: (data: Omit<Task, 'id'>) => void;
    onUpdateTask: (id: string, data: Partial<Task>) => void;
    onDeleteTask: (id: string) => void;
    initialProjectId?: string | null;
    onProjectSelected?: () => void;
}

type ViewMode = 'status' | 'priority';

const PRIORITY_COLUMN_COLORS: { [key in Priority]: string } = {
    [Priority.High]: 'bg-red-200 text-red-800',
    [Priority.Medium]: 'bg-yellow-200 text-yellow-800',
    [Priority.Low]: 'bg-blue-200 text-blue-800',
};

const TaskForm: React.FC<{
    task: Partial<Task> | null;
    assignees: User[];
    projectId: string;
    ras: RA[];
    courseDates: { startDate: string; endDate: string; };
    onSave: (data: any) => void;
    onCancel: () => void;
    onDelete?: (task: Task) => void;
    userRole: Role;
}> = ({ task, assignees, projectId, ras, courseDates, onSave, onCancel, onDelete, userRole }) => {
    const isNewTask = !task?.id;
    const [formData, setFormData] = useState({
        title: task?.title || '',
        description: task?.description || '',
        assigneeId: task?.assigneeId || '',
        status: task?.status || KanbanStatus.Backlog,
        priority: task?.priority || Priority.Medium,
        difficulty: task?.difficulty || Difficulty.Level2,
        startDate: task?.startDate || new Date().toISOString().split('T')[0],
        endDate: task?.endDate || '',
        raId: task?.raId || '',
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave({ ...formData, projectId });
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-gray-700">Título</label>
                <input type="text" name="title" value={formData.title} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required />
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700">Descripción</label>
                <textarea name="description" value={formData.description} onChange={handleChange} rows={3} className="w-full p-2 mt-1 border border-gray-300 rounded-md" />
            </div>
            <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
                <div>
                    <label className="block text-sm font-medium text-gray-700">Asignado a</label>
                    <select name="assigneeId" value={formData.assigneeId} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required>
                        <option value="">Seleccionar miembro</option>
                        {assignees.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700">Estado</label>
                    <select name="status" value={formData.status} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required>
                        {KANBAN_COLUMNS_ORDER.map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700">Prioridad</label>
                    <select name="priority" value={formData.priority} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required>
                        {Object.values(Priority).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700">Nivel de Dificultad</label>
                    <select name="difficulty" value={formData.difficulty} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required>
                        {Object.values(Difficulty).map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                </div>
                {(userRole === Role.Admin || userRole === Role.Tutor) && (
                    <div>
                        <label className="block text-sm font-medium text-gray-700">RA Asociado</label>
                        <select name="raId" value={formData.raId} onChange={handleChange} className="w-full p-2 mt-1 border border-gray-300 rounded-md">
                            <option value="">Seleccionar RA</option>
                            {ras.map(ra => <option key={ra.id} value={ra.id}>{ra.module} / {ra.code}: {ra.description}</option>)}
                        </select>
                    </div>
                )}
                 <div>
                    <label className="block text-sm font-medium text-gray-700">Fecha de Inicio</label>
                    <input type="date" name="startDate" value={formData.startDate} onChange={handleChange} min={courseDates.startDate} max={courseDates.endDate} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required />
                </div>
                 <div>
                    <label className="block text-sm font-medium text-gray-700">Fecha de Fin</label>
                    <input type="date" name="endDate" value={formData.endDate} onChange={handleChange} min={formData.startDate || courseDates.startDate} max={courseDates.endDate} className="w-full p-2 mt-1 border border-gray-300 rounded-md" required />
                </div>
            </div>
            <div className="flex items-center justify-between pt-4">
                <div>
                    {!isNewTask && userRole === Role.Admin && (
                        <button type="button" onClick={() => onDelete?.(task as Task)} className="flex items-center gap-2 px-4 py-2 text-sm text-red-700 bg-red-100 rounded-md hover:bg-red-200">
                           <TrashIcon className="w-4 h-4" /> Eliminar
                        </button>
                    )}
                </div>
                <div className="flex space-x-2">
                    <button type="button" onClick={onCancel} className="px-4 py-2 text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200">Cancelar</button>
                    <button type="submit" className="px-4 py-2 text-white bg-green-600 rounded-md hover:bg-green-700">Guardar Tarea</button>
                </div>
            </div>
        </form>
    );
};

const KanbanColumn: React.FC<{ 
    title: string; 
    headerColor: string;
    tasks: Task[]; 
    ras: RA[];
    onCardClick: (task: Task) => void; 
    userRole: Role;
    viewMode: ViewMode;
}> = ({ title, headerColor, tasks, ras, onCardClick, userRole, viewMode }) => {

    return (
        <div className="flex flex-col">
            <div className="flex items-center justify-between p-2 mb-2">
                <h3 className={`text-sm font-semibold uppercase ${headerColor} px-3 py-1 rounded-full`}>{title}</h3>
                <span className="text-sm font-bold text-gray-500">{tasks.length}</span>
            </div>
            <div className="flex-1 p-2 space-y-4 overflow-y-auto bg-gray-100 rounded-lg min-h-[200px]">
                {tasks.map(task => (
                    <KanbanCard key={task.id} task={task} ras={ras} onClick={() => onCardClick(task)} viewMode={viewMode} />
                ))}
            </div>
        </div>
    );
};


const KanbanBoard: React.FC<KanbanBoardProps> = ({ user, groups, projects, tasks, users, ras, courseDates, onCreateTask, onUpdateTask, onDeleteTask, initialProjectId, onProjectSelected }) => {
    const relevantProjectIds = useMemo(() => {
        if (user.role === Role.Admin) return projects.map(p => p.id);
        if (user.role === Role.Tutor) {
             const tutorGroups = groups.filter(g => g.tutorId === user.id).map(g => g.id);
             return projects.filter(p => tutorGroups.includes(p.groupId)).map(p => p.id);
        }
        return projects.filter(p => user.groupIds.includes(p.groupId)).map(p => p.id);
    }, [user, groups, projects]);

    const [selectedProjectId, setSelectedProjectId] = useState<string>(
        (initialProjectId && relevantProjectIds.includes(initialProjectId))
            ? initialProjectId
            : (relevantProjectIds[0] || '')
    );
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTask, setEditingTask] = useState<Task | null>(null);
    const [taskToDelete, setTaskToDelete] = useState<Task | null>(null);
    const [viewMode, setViewMode] = useState<ViewMode>('status');

    useEffect(() => {
        if (initialProjectId && relevantProjectIds.includes(initialProjectId)) {
            setSelectedProjectId(initialProjectId);
        }
    }, [initialProjectId, relevantProjectIds]);

    const handleProjectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
        setSelectedProjectId(e.target.value);
        if (onProjectSelected) {
            onProjectSelected();
        }
    };

    const filteredTasks = tasks.filter(task => task.projectId === selectedProjectId);

    const sortedTasks = useMemo(() => {
        return [...filteredTasks].sort((a, b) => new Date(a.endDate).getTime() - new Date(b.endDate).getTime());
    }, [filteredTasks]);

    const columns = useMemo(() => {
        if (viewMode === 'status') {
            const groupedTasks = KANBAN_COLUMNS_ORDER.reduce((acc, status) => ({...acc, [status]: []}), {} as Record<KanbanStatus, Task[]>);
            sortedTasks.forEach(task => { if (groupedTasks[task.status]) groupedTasks[task.status].push(task); });
            return groupedTasks;
        } else { // priority view
            const priorityOrder = [Priority.High, Priority.Medium, Priority.Low];
            const groupedTasks = priorityOrder.reduce((acc, priority) => ({...acc, [priority]: []}), {} as Record<Priority, Task[]>);
            sortedTasks.forEach(task => { if (groupedTasks[task.priority]) groupedTasks[task.priority].push(task); });
            return groupedTasks;
        }
    }, [sortedTasks, viewMode]);

    const columnOrder = useMemo(() => (
        viewMode === 'status' 
            ? KANBAN_COLUMNS_ORDER 
            : [Priority.High, Priority.Medium, Priority.Low]
    ), [viewMode]);

    const availableAssignees = useMemo(() => {
        const project = projects.find(p => p.id === selectedProjectId);
        const group = groups.find(g => g.id === project?.groupId);
        return group ? group.members : [];
    }, [selectedProjectId, projects, groups]);

    const handleCreateClick = () => {
        setEditingTask(null);
        setIsModalOpen(true);
    };

    const handleCardClick = (task: Task) => {
        setEditingTask(task);
        setIsModalOpen(true);
    };

    const handleSaveTask = (taskData: any) => {
        if (editingTask) {
            onUpdateTask(editingTask.id, taskData);
        } else {
            onCreateTask(taskData);
        }
        setIsModalOpen(false);
        setEditingTask(null);
    };

    const handleDeleteRequest = (task: Task) => {
        setTaskToDelete(task);
        setIsModalOpen(false);
    };

    const handleConfirmDelete = () => {
        if (taskToDelete) {
            onDeleteTask(taskToDelete.id);
            setTaskToDelete(null);
        }
    };

    return (
        <div className="flex flex-col h-full">
            <div className="flex flex-wrap items-center justify-between gap-4 p-4 mb-4 bg-white rounded-lg shadow-md">
                <div className="flex flex-wrap items-center gap-4">
                    <select value={selectedProjectId} onChange={handleProjectChange} className="p-2 border border-gray-300 rounded-md md:w-80 focus:ring-green-500 focus:border-green-500">
                        {projects.filter(p => relevantProjectIds.includes(p.id)).map(project => (
                            <option key={project.id} value={project.id}>{project.name}</option>
                        ))}
                    </select>
                    <div className="flex items-center p-1 space-x-1 bg-gray-200 rounded-lg">
                        <button onClick={() => setViewMode('status')} className={`px-3 py-1 text-sm font-semibold rounded-md transition-colors ${viewMode === 'status' ? 'bg-green-600 text-white shadow' : 'text-gray-600 hover:bg-white'}`}>Por Estado</button>
                        <button onClick={() => setViewMode('priority')} className={`px-3 py-1 text-sm font-semibold rounded-md transition-colors ${viewMode === 'priority' ? 'bg-green-600 text-white shadow' : 'text-gray-600 hover:bg-white'}`}>Por Prioridad</button>
                    </div>
                </div>
                {(user.role === Role.Admin || user.role === Role.Tutor || user.role === Role.Student) && (
                    <button onClick={handleCreateClick} className="flex items-center gap-2 px-4 py-2 font-semibold text-white bg-green-600 rounded-md hover:bg-green-700">
                        <PlusCircleIcon className="w-5 h-5"/>
                        Añadir Tarea
                    </button>
                )}
            </div>

            <div className="flex-1 overflow-x-auto">
                <div className="grid grid-cols-1 gap-5 md:grid-cols-3 min-w-[800px]">
                    {columnOrder.map(columnKey => (
                         <KanbanColumn
                            key={columnKey}
                            title={columnKey}
                            headerColor={viewMode === 'status' ? STATUS_COLORS[columnKey as KanbanStatus] : PRIORITY_COLUMN_COLORS[columnKey as Priority]}
                            tasks={columns[columnKey as keyof typeof columns]}
                            ras={ras}
                            onCardClick={handleCardClick}
                            userRole={user.role}
                            viewMode={viewMode}
                        />
                    ))}
                </div>
            </div>

            {isModalOpen && (
                <Modal title={editingTask ? "Editar Tarea" : "Crear Nueva Tarea"} onClose={() => setIsModalOpen(false)}>
                    <TaskForm
                        task={editingTask}
                        assignees={availableAssignees}
                        projectId={selectedProjectId}
                        ras={ras}
                        courseDates={courseDates}
                        onSave={handleSaveTask}
                        onCancel={() => setIsModalOpen(false)}
                        onDelete={handleDeleteRequest}
                        userRole={user.role}
                    />
                </Modal>
            )}

            {taskToDelete && (
                <Modal title="Confirmar Eliminación" onClose={() => setTaskToDelete(null)}>
                    <div className="text-center">
                        <p className="text-lg text-gray-700">¿Estás seguro de que quieres eliminar la tarea?</p>
                        <p className="my-2 text-xl font-bold text-red-600">"{taskToDelete.title}"</p>
                        <div className="flex justify-center mt-6 space-x-4">
                            <button onClick={() => setTaskToDelete(null)} className="px-6 py-2 text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200">
                                Cancelar
                            </button>
                            <button onClick={handleConfirmDelete} className="px-6 py-2 text-white bg-red-600 rounded-md hover:bg-red-700">
                                Sí, Eliminar
                            </button>
                        </div>
                    </div>
                </Modal>
            )}
        </div>
    );
};

export default KanbanBoard;

