    tasks: Task[];
    users: User[];
    ras: RA[];
    courseDates: { startDate: string; endDate: string; };
    onCreateTask: (data: Omit<Task, 'id'>) => void;
    onUpdateTask: (id: string, data: Partial<Task>) => void;
    onDeleteTask: (id: string) => void;
