const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 48 }) => {
    const strokeWidth = 6;

    if (progress === 100) {
        return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-green-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-sm font-bold text-white">{progress}%</span>
            </div>
        );
    }

    if (progress === 0) {
         return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-red-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className="absolute text-sm font-bold text-white">{progress}%</span>
            </div>
        );
    }

    const radius = size / 2 - strokeWidth / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    const progressColorClass = useMemo(() => {
        if (progress <= 40) return 'text-red-500';
        if (progress <= 79) return 'text-yellow-500';
        return 'text-green-500';
    }, [progress]);

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg className="absolute" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                <circle className="text-gray-200" strokeWidth={strokeWidth} stroke="currentColor" fill="transparent" r={radius} cx={size/2} cy={size/2} />
                <circle
                    className={progressColorClass}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size/2}
                    cy={size/2}
                    style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    transform={`rotate(-90 ${size/2} ${size/2})`}
                />
            </svg>
            <span className="text-sm font-bold text-gray-700">{progress}%</span>
        </div>
    );
};


interface GanttChartDisplayProps {
    tasks: Task[];
    courseDates: { startDate: string; endDate: string; };
    ras: RA[];
    onUpdateTask: (id: string, data: Partial<Task>) => void;
    onDeleteTask: (id: string) => void;
    user: User;
    availableAssignees: User[];
    projectId: string;
}

const GanttChartDisplay: React.FC<GanttChartDisplayProps> = ({ tasks, courseDates, ras, onUpdateTask, onDeleteTask, user, availableAssignees, projectId }) => {
    const [dayWidth, setDayWidth] = useState(40);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingTask, setEditingTask] = useState<Task | null>(null);
    const [taskToDelete, setTaskToDelete] = useState<Task | null>(null);
    const [sortOption, setSortOption] = useState<'default' | 'priority' | 'status' | 'date'>('status');
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const dayInitials = ['D', 'L', 'M', 'X', 'J', 'V', 'S'];

    const sortedTasks = useMemo(() => {
        const tasksCopy = [...tasks];
        if (sortOption === 'priority') {
            const priorityOrder = { [Priority.High]: 1, [Priority.Medium]: 2, [Priority.Low]: 3 };
            tasksCopy.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);
        } else if (sortOption === 'status') {
            const statusOrder = { [KanbanStatus.Backlog]: 1, [KanbanStatus.Doing]: 2, [KanbanStatus.Done]: 3 };
            tasksCopy.sort((a, b) => statusOrder[a.status] - statusOrder[b.status]);
        } else if (sortOption === 'date') {
            tasksCopy.sort((a, b) => new Date(a.startDate).getTime() - new Date(b.startDate).getTime());
        }
        return tasksCopy;
    }, [tasks, sortOption]);

    const { chartStartDate, chartEndDate, totalDays } = useMemo(() => {
        const startDate = new Date(courseDates.startDate);
        const endDate = new Date(courseDates.endDate);
        const dayInMillis = 1000 * 60 * 60 * 24;
        const diff = (endDate.getTime() - startDate.getTime()) / dayInMillis;
        return { chartStartDate: startDate, chartEndDate: endDate, totalDays: Math.max(0, Math.ceil(diff) + 1) };
    }, [courseDates]);

    const getDaysOffset = (dateStr: string) => {
        if (!dateStr) return 0;
        const date = new Date(dateStr);
        const dayInMillis = 1000 * 60 * 60 * 24;
        return Math.floor((date.getTime() - chartStartDate.getTime()) / dayInMillis);
    };

    const monthHeaders = useMemo(() => {
        if (totalDays === 0) return [];
        const months = []; let currentDate = new Date(chartStartDate); currentDate.setDate(1);
        while (currentDate <= chartEndDate) { months.push(new Date(currentDate)); currentDate.setMonth(currentDate.getMonth() + 1); }
        return months;
    }, [chartStartDate, chartEndDate, totalDays]);

    const handleEditTask = (task: Task) => {
        if (user.role === Role.Admin || user.role === Role.Tutor || user.role === Role.Student) {
             setEditingTask(task);
             setIsModalOpen(true);
        }
    };

    const handleScrollToTask = (task: Task) => {
        const minDayWidth = 15;
        setDayWidth(minDayWidth);
        if (scrollContainerRef.current) {
            const startOffset = getDaysOffset(task.startDate);
            const scrollPosition = startOffset * minDayWidth;
            scrollContainerRef.current.scrollTo({
                left: scrollPosition,
                behavior: 'smooth',
            });
        }
    };

    const handleSaveTask = (taskData: any) => {
        if (editingTask) { onUpdateTask(editingTask.id, taskData); }
        setIsModalOpen(false); setEditingTask(null);
    };

    const handleDeleteRequest = (task: Task) => {
        setTaskToDelete(task); setIsModalOpen(false);
    };

    const handleConfirmDelete = () => {
        if (taskToDelete) { onDeleteTask(taskToDelete.id); setTaskToDelete(null); }
    };

    const getRowBgColor = (task: Task) => {
        if (sortOption === 'priority') {
            return PRIORITY_BACKGROUND_COLORS[task.priority];
        }
        return STATUS_BACKGROUND_COLORS[task.status];
    };


    return (
        <>
            <div className="flex flex-wrap items-center justify-between gap-4 p-2 shrink-0">
                {sortedTasks.length > 0 && <GanttLegend sortOption={sortOption} />}
                <div className="flex items-center gap-4">
                    <div>
                        <label htmlFor="gantt-sort" className="mr-2 text-sm font-semibold text-gray-600">Ordenar por:</label>
                        <select
                            id="gantt-sort"
                            value={sortOption}
                            onChange={(e) => setSortOption(e.target.value as 'default' | 'priority' | 'status' | 'date')}
                            className="p-1 text-sm bg-white border border-gray-300 rounded-md focus:outline-none focus:ring-1 focus:ring-green-500"
                        >
                            <option value="default">Defecto</option>
                            <option value="priority">Por Prioridad</option>
                            <option value="status">Por Estado</option>
                            <option value="date">Por Fecha</option>
                        </select>
                    </div>
                    <div className="flex items-center gap-2">
                        <span className="text-sm font-semibold text-gray-600">Zoom:</span>
                        <button onClick={() => setDayWidth(w => Math.max(15, w - 5))} className="px-3 py-1 font-bold text-gray-700 bg-gray-200 rounded-md hover:bg-gray-300">-</button>
                        <button onClick={() => setDayWidth(w => Math.min(100, w + 5))} className="px-3 py-1 font-bold text-gray-700 bg-gray-200 rounded-md hover:bg-gray-300">+</button>
                    </div>
                </div>
            </div>
            <div ref={scrollContainerRef} className="flex-grow mt-0 overflow-auto">
                <div className="grid min-w-max" style={{
                    gridTemplateColumns: `minmax(250px, 1.5fr) repeat(${totalDays}, ${dayWidth}px)`,
                    gridTemplateRows: `40px 25px 25px repeat(${sortedTasks.length > 0 ? sortedTasks.length : 1}, 40px)`
                }}>
                    <div className="sticky top-0 left-0 z-30 bg-gray-200 border-b border-r" style={{ gridRow: 1, gridColumn: 1 }}></div>

                    {monthHeaders.map((month) => {
                        const monthStart = new Date(month); const nextMonthStart = new Date(month); nextMonthStart.setMonth(nextMonthStart.getMonth() + 1);
                        const startOffset = getDaysOffset(monthStart.toISOString().split('T')[0]); const endOffset = getDaysOffset(nextMonthStart.toISOString().split('T')[0]);
                        const colStart = Math.max(0, startOffset); const colEnd = Math.min(totalDays, endOffset); const colSpan = colEnd - colStart;
                        if (colSpan <= 0) return null;
                        return (
                            <div key={month.getTime()} className="sticky top-0 z-20 flex items-center justify-center text-sm font-semibold text-gray-700 bg-gray-200 border-b border-r" style={{ gridColumn: `${colStart + 2} / span ${colSpan}`, gridRow: 1 }}>
                                {month.toLocaleString('es-ES', { month: 'long', year: 'numeric' }).toUpperCase()}
                            </div>
                        );
                    })}

                    <div className="sticky top-[40px] left-0 z-20 flex items-center justify-center font-semibold text-center text-gray-700 bg-gray-100 border-b border-r" style={{gridRow: '2 / span 2', gridColumn: 1}}>Tarea</div>

                    {Array.from({ length: totalDays }).map((_, i) => {
                        const date = new Date(chartStartDate); date.setDate(date.getDate() + i); const isWeekend = date.getDay() === 0 || date.getDay() === 6;
                        return (<div key={i} style={{gridRow: 2}} className={`sticky top-[40px] z-10 text-xs text-center text-gray-700 border-b border-r h-full flex items-center justify-center ${isWeekend ? 'bg-red-100' : 'bg-gray-50'}`}>{date.getDate()}</div>);
                    })}

                    {Array.from({ length: totalDays }).map((_, i) => {
                        const date = new Date(chartStartDate); date.setDate(date.getDate() + i); const isWeekend = date.getDay() === 0 || date.getDay() === 6;
                        return (
                            <div key={`initial-${i}`} style={{gridRow: 3}} className={`sticky top-[65px] z-10 text-xs font-semibold h-full flex items-center justify-center border-b border-r ${isWeekend ? 'text-red-700 bg-red-100' : 'text-gray-600 bg-gray-100'}`}>
                                {dayInitials[date.getDay()]}
                            </div>
                        );
                    })}

                    {sortedTasks.map((task, index) => {
                        const startOffset = getDaysOffset(task.startDate); const duration = getDaysOffset(task.endDate) - startOffset + 1;
                        const taskBarColor = GANTT_BAR_COLORS[task.status];
                        if (startOffset < 0 || startOffset >= totalDays || duration <= 0) return null;
                        const canEdit = user.role === Role.Admin || user.role === Role.Tutor || user.role === Role.Student;
                        const rowNumber = index + 4;
                        return (
                            <React.Fragment key={task.id}>
                                <div className={`sticky left-0 z-10 flex items-center justify-between w-full h-full p-2 text-sm text-left border-b border-r ${getRowBgColor(task)}`} style={{ gridRow: rowNumber, gridColumn: 1 }}>
                                    <span onClick={() => handleScrollToTask(task)} className="flex-grow truncate cursor-pointer" title={task.title}>
                                        {task.title}
                                    </span>
                                    {canEdit && (
                                        <button
                                            onClick={(e) => { e.stopPropagation(); handleEditTask(task); }}
                                            className="flex-shrink-0 p-1 ml-2 rounded-full hover:bg-black/10"
                                            aria-label={`Editar tarea ${task.title}`}
                                        >
                                            <EditIcon className="w-4 h-4" />
                                        </button>
                                    )}
                                </div>
                                <div className="relative border-b" style={{ gridColumn: `2 / span ${totalDays}`, gridRow: rowNumber }} >
                                    <div className="absolute inset-0 grid" style={{ gridTemplateColumns: `repeat(${totalDays}, ${dayWidth}px)`}}>
                                        {Array.from({ length: totalDays }).map((_, i) => {
                                            const date = new Date(chartStartDate); date.setDate(date.getDate() + i);
                                            const isEvenMonth = date.getMonth() % 2 === 0;
                                            const isWeekend = date.getDay() === 0 || date.getDay() === 6;
                                            let bgColorClass = isWeekend ? 'bg-red-50' : isEvenMonth ? 'bg-gray-50' : 'bg-white';
                                            return <div key={i} className={`${bgColorClass} border-r border-gray-200`}></div>
                                        })}
                                    </div>
                                    <div style={{ position: 'absolute', left: `calc(${dayWidth}px * ${startOffset})`, width: `calc(${dayWidth}px * ${duration})`, top: '0.25rem', bottom: '0.25rem', zIndex: 1 }} className={`flex items-center justify-start h-auto p-1 text-xs font-semibold rounded-md ${taskBarColor}`} title={`${task.title} (${task.startDate} - ${task.endDate})`}>
                                        <span className="pl-2 truncate">{task.title}</span>
                                    </div>
                                </div>
                            </React.Fragment>
                        );
                    })}
                    {tasks.length === 0 && <div className="py-10 text-center text-gray-500" style={{ gridColumn: '1 / -1', gridRow: 4 }}>No hay tareas para mostrar en el diagrama de Gantt.</div>}
                </div>
            </div>

            {isModalOpen && editingTask && (
                <Modal title="Editar Tarea" onClose={() => setIsModalOpen(false)}>
                    <GanttTaskForm task={editingTask} assignees={availableAssignees} projectId={projectId} ras={ras} courseDates={courseDates} onSave={handleSaveTask} onCancel={() => setIsModalOpen(false)} onDelete={handleDeleteRequest} userRole={user.role} />
                </Modal>
            )}
            {taskToDelete && (
                <Modal title="Confirmar Eliminación" onClose={() => setTaskToDelete(null)}>
                    <div className="text-center">
                        <p className="text-lg text-gray-700">¿Estás seguro de que quieres eliminar la tarea?</p>
                        <p className="my-2 text-xl font-bold text-red-600">"{taskToDelete.title}"</p>
                        <div className="flex justify-center mt-6 space-x-4">
                            <button onClick={() => setTaskToDelete(null)} className="px-6 py-2 text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200">Cancelar</button>
                            <button onClick={handleConfirmDelete} className="px-6 py-2 text-white bg-red-600 rounded-md hover:bg-red-700">Sí, Eliminar</button>
                        </div>
                    </div>
                </Modal>
            )}
        </>
    );
};

interface GanttChartProps {
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    allUsers: User[];
    courseDates: { startDate: string; endDate: string; };
    ras: RA[];
    onUpdateTask: (id: string, data: Partial<Task>) => void;
    onDeleteTask: (id: string) => void;
}

const GanttChart: React.FC<GanttChartProps> = ({ user, groups, projects, tasks, courseDates, allUsers, ras, onUpdateTask, onDeleteTask }) => {
    const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
    const [expandedCourseGroups, setExpandedCourseGroups] = useState<Record<string, boolean>>({});

    const studentProjects = useMemo(() => {
        if (user.role !== Role.Student) return [];
        return projects
            .filter(p => user.groupIds.includes(p.groupId))
            .map(project => ({
                project,
                group: groups.find(g => g.id === project.groupId)
            }))
            .filter((item): item is { project: Project; group: Group } => !!item.group);
    }, [user, projects, groups]);

    const projectsByCourseGroup = useMemo(() => {
        if (user.role === Role.Student) return {};
        const result: Record<string, Project[]> = {};
        const visibleProjects = user.role === Role.Admin ? projects : projects.filter(p => {
            const group = groups.find(g => g.id === p.groupId);
            if (!group) return false;
            return user.role === Role.Tutor ? group.tutorId === user.id : user.groupIds.includes(group.id);
        });
        visibleProjects.forEach(project => {
            const group = groups.find(g => g.id === project.groupId);
            if (group && group.members.length > 0) {
                let projectCourseGroup = 'Curso no definido';
                for (const member of group.members) {
                    const freshMember = allUsers.find(u => u.id === member.id);
                    if (freshMember && freshMember.courseGroup) { projectCourseGroup = freshMember.courseGroup; break; }
                }
                if (!result[projectCourseGroup]) result[projectCourseGroup] = [];
                result[projectCourseGroup].push(project);
            }
        });
        return result;
    }, [projects, groups, allUsers, user]);

    const toggleCourseGroup = (courseGroupName: string) => setExpandedCourseGroups(prev => ({ ...prev, [courseGroupName]: !prev[courseGroupName] }));

    const selectedProject = projects.find(p => p.id === selectedProjectId);
    const visibleTasks = tasks.filter(t => t.projectId === selectedProjectId);

    if (selectedProject) {
        const projectGroup = groups.find(g => g.id === selectedProject.groupId);
        const assignees = projectGroup?.members || [];
        return (
            <div className="flex flex-col h-full p-4 bg-white rounded-lg shadow-md">
                <div className="flex items-center justify-between pb-4 border-b shrink-0">
                    <h2 className="text-xl font-bold text-gray-800">Gantt: <span className="text-green-700">{selectedProject.name}</span></h2>
                    <button onClick={() => setSelectedProjectId(null)} className="px-4 py-2 text-sm font-semibold text-white bg-green-600 rounded-md hover:bg-green-700">← Volver a la selección</button>
                </div>
                <GanttChartDisplay tasks={visibleTasks} courseDates={courseDates} ras={ras} onUpdateTask={onUpdateTask} onDeleteTask={onDeleteTask} user={user} availableAssignees={assignees} projectId={selectedProject.id} />
            </div>
        );
    }

    return (
        <div className="p-4 bg-white rounded-lg shadow-md">
            <h2 className="pb-4 mb-4 text-xl font-bold text-gray-800 border-b">Seleccione un proyecto para ver su Diagrama de Gantt</h2>

            {user.role === Role.Student ? (
                <div className="space-y-2">
                    {studentProjects.length > 0 ? studentProjects.map(({ project, group }) => {
                        const projectTasks = tasks.filter(t => t.projectId === project.id);
                        const completedTasks = projectTasks.filter(t => t.status === KanbanStatus.Done).length;
                        const totalTasks = projectTasks.length;
                        const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;
                        const tutor = allUsers.find(u => u.id === group.tutorId);

                        return (
                            <button 
                                key={project.id} 
                                onClick={() => setSelectedProjectId(project.id)} 
                                className="flex items-center w-full p-3 text-left text-gray-700 transition-colors bg-white border rounded-md shadow-sm gap-4 hover:bg-green-50 hover:border-green-300"
                            >
                                <div>
                                    <ProgressCircle progress={progress} size={48} />
                                </div>
                                <div className="flex-grow min-w-0">
                                    <p className="font-semibold text-green-800 truncate">{project.name}</p>
                                    <p className="text-sm text-gray-500">{group.name}</p>
                                    <p className="mt-1 text-xs text-gray-500">Tutor: {tutor ? tutor.name : 'Sin tutor'}</p>
                                </div>
                                <div className="flex flex-col items-end flex-shrink-0">
                                    <div>
                                        <p className="text-sm font-medium text-gray-800">{new Date(project.startDate).toLocaleDateString('es-ES')}</p>
                                        <p className="text-xs text-right text-gray-500">Inicio</p>
                                    </div>
                                    <div className="mt-1">
                                        <p className="text-sm font-medium text-gray-800">{new Date(project.endDate).toLocaleDateString('es-ES')}</p>
                                        <p className="text-xs text-right text-gray-500">Fin</p>
                                    </div>
                                </div>
                            </button>
                        );
                    }) : <p className="text-center text-gray-500">No estás asignado a ningún proyecto.</p>}
                </div>
            ) : (
                <div className="space-y-2">
                    {Object.keys(projectsByCourseGroup).sort().map(courseGroup => {
                        const courseProjects = projectsByCourseGroup[courseGroup]; const isExpanded = !!expandedCourseGroups[courseGroup];
                        return (
                            <div key={courseGroup} className="border border-gray-200 rounded-lg">
                                <button onClick={() => toggleCourseGroup(courseGroup)} className="flex items-center justify-between w-full p-4 text-left bg-gray-50 hover:bg-gray-100 focus:outline-none">
                                    <div className="flex items-center">
                                        <h3 className="text-lg font-semibold text-gray-800">{courseGroup}</h3>
                                        <span className="ml-4 px-3 py-1 text-sm font-semibold text-green-800 bg-green-100 rounded-full">{courseProjects.length} {courseProjects.length === 1 ? 'proyecto' : 'proyectos'}</span>
                                    </div>
                                    <ChevronDownIcon className={`w-6 h-6 text-gray-500 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                                </button>
                                {isExpanded && (
                                    <div className="p-2 border-t border-gray-200 md:p-4">
                                        <div className="space-y-2">
                                            {courseProjects.map(project => {
                                                const group = groups.find(g => g.id === project.groupId);
                                                const tutor = allUsers.find(u => u.id === group?.tutorId);
                                                const projectTasks = tasks.filter(t => t.projectId === project.id);
                                                const completedTasks = projectTasks.filter(t => t.status === KanbanStatus.Done).length;
                                                const totalTasks = projectTasks.length;
                                                const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

                                                return (
                                                    <button 
                                                        key={project.id} 
                                                        onClick={() => setSelectedProjectId(project.id)} 
                                                        className="flex items-center w-full p-3 text-left text-gray-700 transition-colors bg-white border rounded-md shadow-sm gap-4 hover:bg-green-50 hover:border-green-300"
                                                    >
                                                        <div>
                                                            <ProgressCircle progress={progress} size={48} />
                                                        </div>
                                                        <div className="flex-grow min-w-0">
                                                            <p className="font-semibold text-green-800 truncate">{project.name}</p>
                                                            <p className="text-sm text-gray-500">{group?.name}</p>
                                                            <p className="mt-1 text-xs text-gray-500">Tutor: {tutor ? tutor.name : 'Sin tutor'}</p>
                                                        </div>
                                                        <div className="flex flex-col items-end flex-shrink-0">
                                                            <div>
                                                                <p className="text-sm font-medium text-gray-800">{new Date(project.startDate).toLocaleDateString('es-ES')}</p>
                                                                <p className="text-xs text-right text-gray-500">Inicio</p>
                                                            </div>
                                                            <div className="mt-1">
                                                                <p className="text-sm font-medium text-gray-800">{new Date(project.endDate).toLocaleDateString('es-ES')}</p>
                                                                <p className="text-xs text-right text-gray-500">Fin</p>
                                                            </div>
                                                        </div>
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

export default GanttChart;

import React, { useState, useMemo } from 'react';
import { User, Task, Role, KanbanStatus, Group, Project, Message, Tutorial, Priority, Difficulty } from '../types';
import { ChevronDownIcon } from './Icons';
import PendingMessagesModal from './PendingMessagesModal';

interface DashboardProps {
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    allUsers: User[];
    messages: Message[];
    tutorials: Tutorial[];
    onNavigateToKanban: (projectId: string) => void;
    onSendMessage: (messageData: any) => void;
    onMarkMessagesAsRead: (messageIds: string[]) => void;
}

// --- Componentes para la vista de Administrador y Tutor ---

const CountdownDisplay: React.FC<{ endDate: string }> = ({ endDate }) => {
    const timeLeft = useMemo(() => {
        const difference = +new Date(endDate) - +new Date();
        if (difference <= 0) {
            return { overdue: true, weeks: 0, days: 0 };
        }
        const totalDays = Math.ceil(difference / (1000 * 60 * 60 * 24));
        const weeks = Math.floor(totalDays / 7);
        const days = totalDays % 7;
        return { overdue: false, weeks, days };
    }, [endDate]);

    if (timeLeft.overdue) {
        return (
            <div className="text-center">
                <p className="text-sm font-medium text-gray-500">Estado</p>
                <p className="text-base font-bold text-red-600">Finalizado</p>
            </div>
        );
    }

    const weeksText = timeLeft.weeks === 1 ? 'semana' : 'semanas';
    const daysText = timeLeft.days === 1 ? 'día' : 'días';

    return (
        <div className="text-center">
             <p className="text-sm font-medium text-gray-500">Tiempo restante para finalizar</p>
             <p className="text-base font-bold text-yellow-600">{`${timeLeft.weeks} ${weeksText} + ${timeLeft.days} ${daysText}`}</p>
        </div>
    );
};

const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 64 }) => {
    const strokeWidth = size < 50 ? 6 : 8;

    if (progress === 100) {
        return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-green-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className={`absolute font-bold text-white ${size < 50 ? 'text-xs' : 'text-base'}`}>{progress}%</span>
            </div>
        );
    }

    if (progress <= 0) {
         return (
            <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
                <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                    <circle
                        className="text-red-500"
                        fill="currentColor"
                        r={size / 2}
                        cx={size / 2}
                        cy={size / 2}
                    />
                </svg>
                <span className={`absolute font-bold text-white ${size < 50 ? 'text-xs' : 'text-base'}`}>{progress}%</span>
            </div>
        );
    }

    const radius = size / 2 - strokeWidth / 2;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    const progressColorClass = useMemo(() => {
        if (progress <= 40) return 'text-red-500';
        if (progress <= 79) return 'text-yellow-500';
        return 'text-green-500';
    }, [progress]);

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg className="absolute" width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
                <circle className="text-gray-200" strokeWidth={strokeWidth} stroke="currentColor" fill="transparent" r={radius} cx={size/2} cy={size/2} />
                <circle
                    className={progressColorClass}
                    strokeWidth={strokeWidth}
                    strokeDasharray={circumference}
                    strokeDashoffset={offset}
                    strokeLinecap="round"
                    stroke="currentColor"
                    fill="transparent"
                    r={radius}
                    cx={size/2}
                    cy={size/2}
                    style={{ transition: 'stroke-dashoffset 0.5s ease-in-out' }}
                    transform={`rotate(-90 ${size/2} ${size/2})`}
                />
            </svg>
            <span className={`font-bold text-gray-700 ${size < 50 ? 'text-xs' : 'text-base'}`}>{progress}%</span>
        </div>
    );
};

const difficultyWeights: { [key in Difficulty]: number } = {
    [Difficulty.Level1]: 1,
    [Difficulty.Level2]: 2,
    [Difficulty.Level3]: 3,
};

const priorityWeights: { [key in Priority]: number } = {
    [Priority.Low]: 1,
    [Priority.Medium]: 1.5,
    [Priority.High]: 2,
};

const AdminTutorGroupCard: React.FC<{ 
    group: Group; 
    project: Project; 
    tasks: Task[]; 
    allUsers: User[]; 
    tutorials: Tutorial[];
    onNavigateToKanban: (id: string) => void;
}> = ({ group, project, tasks, allUsers, tutorials, onNavigateToKanban }) => {
    const { progress, totalTasks, pendingTasks, inProgressTasks, completedTasks } = useMemo(() => {
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const pending = groupTasks.filter(t => t.status === KanbanStatus.Backlog).length;
        return {
            progress: total > 0 ? Math.round((completed / total) * 100) : 0,
            totalTasks: total,
            pendingTasks: pending,
            inProgressTasks: inProgress,
            completedTasks: completed,
        };
    }, [project, tasks]);

    const tutor = useMemo(() => allUsers.find(u => u.id === group.tutorId), [allUsers, group.tutorId]);

    const freshGroupMembers = useMemo(() => {
        return group.members
            .map(staleMember => allUsers.find(freshUser => freshUser.id === staleMember.id))
            .filter((member): member is User => !!member);
    }, [group.members, allUsers]);

    const courseGroup = useMemo(() => {
        if (freshGroupMembers.length > 0) {
            for (const member of freshGroupMembers) {
                if (member.courseGroup) {
                    return member.courseGroup;
                }
            }
        }
        return 'Curso no definido';
    }, [freshGroupMembers]);

    const { pastTutorialsCount, nextTutorialDate } = useMemo(() => {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const groupTutorials = tutorials.filter(t => t.groupId === group.id);
        const pastTutorials = groupTutorials.filter(t => new Date(t.date + 'T00:00:00') < today);
        const futureTutorials = groupTutorials
            .filter(t => t.nextDate && new Date(t.nextDate + 'T00:00:00') >= today)
            .sort((a, b) => new Date(a.nextDate).getTime() - new Date(b.nextDate).getTime());

        const nextDateInfo = futureTutorials.length > 0
            ? `${new Date(futureTutorials[0].nextDate + 'T00:00:00').toLocaleDateString('es-ES')} ${futureTutorials[0].nextTime ? `a las ${futureTutorials[0].nextTime}`: ''}`
            : 'No agendada';

        return { pastTutorialsCount: pastTutorials.length, nextTutorialDate: nextDateInfo };
    }, [tutorials, group.id]);

    const groupMeetingsCount = 0; // Placeholder
    const nextGroupMeetingDate = "No agendada"; // Placeholder

    const calculateTaskStats = (tasks: Task[]) => {
        const stats = {
            tasks,
            count: tasks.length,
            byDifficulty: {
                [Difficulty.Level1]: 0,
                [Difficulty.Level2]: 0,
                [Difficulty.Level3]: 0,
            }
        };
        tasks.forEach(task => {
            if (stats.byDifficulty[task.difficulty] !== undefined) {
                stats.byDifficulty[task.difficulty]++;
            }
        });
        return stats;
    };

    const memberStats = useMemo(() => {
        const statsMap = new Map<string, { name: string; completed: Task[]; inProgress: Task[]; pending: Task[]; }>();
        const projectTasks = tasks.filter(task => task.projectId === project.id);
        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const ptg = projectTasks.reduce((acc, task) => {
            const d = difficultyWeights[task.difficulty];
            const p = priorityWeights[task.priority];
            return acc + (d * p);
        }, 0);

        freshGroupMembers.forEach(member => {
            if (member.role === Role.Student) {
                statsMap.set(member.id, { name: member.name, completed: [], inProgress: [], pending: [] });
            }
        });

        projectTasks.forEach(task => {
            if (task.assigneeId && statsMap.has(task.assigneeId)) {
                const memberStat = statsMap.get(task.assigneeId)!;
                switch (task.status) {
                    case KanbanStatus.Done: memberStat.completed.push(task); break;
                    case KanbanStatus.Doing: memberStat.inProgress.push(task); break;
                    case KanbanStatus.Backlog: memberStat.pending.push(task); break;
                }
            }
        });

        const result = Array.from(statsMap.entries()).map(([id, statData]) => {
            const pendingStats = calculateTaskStats(statData.pending);
            const inProgressStats = calculateTaskStats(statData.inProgress);
            const completedStats = calculateTaskStats(statData.completed);
            const allTasks = [...statData.pending, ...statData.inProgress, ...statData.completed];
            const totalStats = calculateTaskStats(allTasks);

            const ca = allTasks.reduce((acc, task) => {
                return acc + (difficultyWeights[task.difficulty] * priorityWeights[task.priority]);
            }, 0);

            const pl = allTasks.reduce((acc, task) => {
                const d = difficultyWeights[task.difficulty];
                const p = priorityWeights[task.priority];
                let e = 0;
                if (task.status === KanbanStatus.Doing) {
                    e = 0.5;
                } else if (task.status === KanbanStatus.Done) {
                    const endDate = new Date(task.endDate + 'T00:00:00');
                    e = endDate < today ? 0.8 : 1.0;
                }
                return acc + (d * p * e);
            }, 0);

            let productivity = 0;
            if (ca > 0 && ptg > 0) {
                productivity = ((pl / ptg) * (pl / ca)) * 100;
            }

            return {
                id,
                name: statData.name,
                completed: completedStats,
                inProgress: inProgressStats,
                pending: pendingStats,
                totalAssigned: totalStats,
                productivity: Math.round(productivity),
            };
        });

        return result.sort((a, b) => b.totalAssigned.count - a.totalAssigned.count);
    }, [freshGroupMembers, tasks, project.id]);

    const difficultyConfig: { [key in Difficulty]: { bg: string, text: string, name: string } } = {
        [Difficulty.Level1]: { bg: 'bg-green-200', text: 'text-green-800', name: 'Sencilla' },
        [Difficulty.Level2]: { bg: 'bg-yellow-200', text: 'text-yellow-800', name: 'Moderada' },
        [Difficulty.Level3]: { bg: 'bg-red-200', text: 'text-red-800', name: 'Compleja' },
    };

    return (
        <div className="w-full p-4 bg-white rounded-lg shadow-md">
            <div onClick={() => onNavigateToKanban(project.id)} className="cursor-pointer">
                <div className="flex flex-col sm:flex-row items-stretch gap-6">
                    <div className="flex-shrink-0 flex items-center justify-center">
                        <ProgressCircle progress={progress} size={96} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-xl font-bold text-green-700">{project.name}</h3>
                        <p className="text-base text-gray-500">{courseGroup} - {group.name}</p>
                        {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                        <div className="pt-2 mt-2 border-t border-gray-200">
                            <h4 className="mb-1 text-sm font-semibold text-gray-600">Componentes del Grupo:</h4>
                            <div className="flex flex-wrap gap-x-4 gap-y-1">
                                {freshGroupMembers
                                    .filter(member => member.role === Role.Student)
                                    .map(member => (
                                    <span key={member.id} className="text-sm text-gray-800">{member.name}</span>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2 pt-3 mt-3 border-t md:grid-cols-3 border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Inicio de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.startDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Fin de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.endDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>

                <div className="pt-3 mt-3 border-t border-gray-200">
                    <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Reuniones de Grupo</p>
                            <p className="text-2xl font-bold text-blue-600">{groupMeetingsCount}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Reunión Grupo</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextGroupMeetingDate}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Tutorías Realizadas</p>
                            <p className="text-2xl font-bold text-blue-600">{pastTutorialsCount}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Tutoría</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextTutorialDate}</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 pt-3 mt-3 border-t border-gray-200">
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-gray-800">{totalTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Tareas Totales</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-red-600">{pendingTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Pendientes</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-blue-600">{inProgressTasks}</p>
                    <p className="text-sm font-medium text-gray-500">En Curso</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-green-600">{completedTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Completadas</p>
                </div>
            </div>

            <div className="pt-3 mt-3 border-t border-gray-200">
                <div className="flex flex-wrap items-center justify-between gap-2 mb-3">
                    <h4 className="text-lg font-bold text-gray-700">Rendimiento del Grupo por Tareas</h4>
                    <div className="flex items-center space-x-4">
                        <span className="text-xs font-semibold text-gray-500">Dificultad:</span>
                        {(Object.keys(difficultyConfig) as Difficulty[]).map(level => (
                            <div key={level} className="flex items-center space-x-1.5">
                                <div className={`w-3 h-3 rounded-full ${difficultyConfig[level].bg}`}></div>
                                <span className="text-xs text-gray-600">{difficultyConfig[level].name}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="hidden md:flex mb-2">
                    <div className="w-full md:w-1/3" /> {/* Spacer */}
                    <div className="flex w-full md:w-2/3">
                        <div className="flex-1 text-center text-xs font-bold text-gray-500">Total</div>
                        <div className="flex-1 text-center text-xs font-bold text-red-600">Pendientes</div>
                        <div className="flex-1 text-center text-xs font-bold text-blue-600">En Progreso</div>
                        <div className="flex-1 text-center text-xs font-bold text-green-600">Realizadas</div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2">
                    {memberStats.map(stat => {
                        const name = stat.name;
                        const firstSpaceIndex = name.indexOf(' ');
                        const firstName = firstSpaceIndex === -1 ? name : name.substring(0, firstSpaceIndex);
                        const lastName = firstSpaceIndex === -1 ? '' : name.substring(firstSpaceIndex + 1);

                        return (
                            <div key={stat.id} className="flex items-center p-2 bg-gray-50 rounded-lg border border-gray-200">
                                <div className="flex items-center w-1/3">
                                    <div className="flex-shrink-0" title={`Productividad: ${stat.productivity}%`}>
                                        <ProgressCircle progress={stat.productivity} size={40} />
                                    </div>
                                    <div className="ml-3 flex-1 min-w-0" title={stat.name}>
                                        <p className="font-medium text-gray-800 truncate">{firstName}</p>
                                        {lastName && <p className="text-sm text-gray-600 truncate">{lastName}</p>}
                                    </div>
                                </div>
                                <div className="flex justify-around w-2/3">
                                    <StatusColumn title="Total de Tareas" mainCircleClass="bg-black" stats={stat.totalAssigned} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Pendientes" mainCircleClass="bg-red-500" stats={stat.pending} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas En Progreso" mainCircleClass="bg-blue-600" stats={stat.inProgress} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Realizadas" mainCircleClass="bg-green-600" stats={stat.completed} difficultyConfig={difficultyConfig} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};


