const StudentProjectDetailCard: React.FC<{
    group: Group;
    project: Project;
    tasks: Task[];
    tutorials: Tutorial[];
    allUsers: User[];
    user: User;
    onNavigateToKanban: (projectId: string) => void;
}> = ({ group, project, tasks, tutorials, allUsers, user, onNavigateToKanban }) => {
    const { progress, totalTasks, pendingTasks, inProgressTasks, completedTasks } = useMemo(() => {
        const groupTasks = tasks.filter(t => t.projectId === project.id);
        const total = groupTasks.length;
        const completed = groupTasks.filter(t => t.status === KanbanStatus.Done).length;
        const inProgress = groupTasks.filter(t => t.status === KanbanStatus.Doing).length;
        const pending = groupTasks.filter(t => t.status === KanbanStatus.Backlog).length;
        return {
            progress: total > 0 ? Math.round((completed / total) * 100) : 0,
            totalTasks: total,
            pendingTasks: pending,
            inProgressTasks: inProgress,
            completedTasks: completed,
        };
    }, [project, tasks]);

    const tutor = useMemo(() => allUsers.find(u => u.id === group.tutorId), [allUsers, group.tutorId]);

    const freshGroupMembers = useMemo(() => {
        return group.members
            .map(staleMember => allUsers.find(freshUser => freshUser.id === staleMember.id))
            .filter((member): member is User => !!member);
    }, [group.members, allUsers]);

    const { pastTutorialsCount, nextTutorialDate } = useMemo(() => {
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const groupTutorials = tutorials.filter(t => t.groupId === group.id);
        const pastTutorials = groupTutorials.filter(t => new Date(t.date + 'T00:00:00') < today);
        const futureTutorials = groupTutorials
            .filter(t => t.nextDate && new Date(t.nextDate + 'T00:00:00') >= today)
            .sort((a, b) => new Date(a.nextDate).getTime() - new Date(b.nextDate).getTime());

        const nextDateInfo = futureTutorials.length > 0
            ? `${new Date(futureTutorials[0].nextDate + 'T00:00:00').toLocaleDateString('es-ES')} ${futureTutorials[0].nextTime ? `a las ${futureTutorials[0].nextTime}`: ''}`
            : 'No agendada';

        return { pastTutorialsCount: pastTutorials.length, nextTutorialDate: nextDateInfo };
    }, [tutorials, group.id]);

    const groupMeetingsCount = 0; // Placeholder
    const nextGroupMeetingDate = "No agendada"; // Placeholder

    const calculateTaskStats = (tasks: Task[]) => {
        const stats = {
            tasks,
            count: tasks.length,
            byDifficulty: {
                [Difficulty.Level1]: 0,
                [Difficulty.Level2]: 0,
                [Difficulty.Level3]: 0,
            }
        };
        tasks.forEach(task => {
            if (stats.byDifficulty[task.difficulty] !== undefined) {
                stats.byDifficulty[task.difficulty]++;
            }
        });
        return stats;
    };

    const memberStats = useMemo(() => {
        const statsMap = new Map<string, { name: string; completed: Task[]; inProgress: Task[]; pending: Task[]; }>();
        const projectTasks = tasks.filter(task => task.projectId === project.id);
        const today = new Date();
        today.setHours(0, 0, 0, 0);
        const numStudents = freshGroupMembers.filter(member => member.role === Role.Student).length;

        const ptg = projectTasks.reduce((acc, task) => {
            const d = difficultyWeights[task.difficulty];
            const p = priorityWeights[task.priority];
            return acc + (d * p);
        }, 0);

        freshGroupMembers.forEach(member => {
            if (member.role === Role.Student) {
                statsMap.set(member.id, { name: member.name, completed: [], inProgress: [], pending: [] });
            }
        });

        projectTasks.forEach(task => {
            if (task.assigneeId && statsMap.has(task.assigneeId)) {
                const memberStat = statsMap.get(task.assigneeId)!;
                switch (task.status) {
                    case KanbanStatus.Done: memberStat.completed.push(task); break;
                    case KanbanStatus.Doing: memberStat.inProgress.push(task); break;
                    case KanbanStatus.Backlog: memberStat.pending.push(task); break;
                }
            }
        });

        const result = Array.from(statsMap.entries()).map(([id, statData]) => {
            const pendingStats = calculateTaskStats(statData.pending);
            const inProgressStats = calculateTaskStats(statData.inProgress);
            const completedStats = calculateTaskStats(statData.completed);
            const allTasks = [...statData.pending, ...statData.inProgress, ...statData.completed];
            const totalStats = calculateTaskStats(allTasks);

            const ca = allTasks.reduce((acc, task) => {
                return acc + (difficultyWeights[task.difficulty] * priorityWeights[task.priority]);
            }, 0);

            const pl = allTasks.reduce((acc, task) => {
                const d = difficultyWeights[task.difficulty];
                const p = priorityWeights[task.priority];
                let e = 0;
                if (task.status === KanbanStatus.Doing) {
                    e = 0.5;
                } else if (task.status === KanbanStatus.Done) {
                    const endDate = new Date(task.endDate + 'T00:00:00');
                    e = endDate < today ? 0.8 : 1.0;
                }
                return acc + (d * p * e);
            }, 0);

            let studentProductivityPercentage = 0;
            if (ca > 0 && ptg > 0) {
                studentProductivityPercentage = ((pl / ptg) * (pl / ca)) * 100;
            }

            let finalDisplayPercentage = 0;
            if (numStudents > 0) {
                const expectedAveragePercentage = 100 / numStudents;
                if (expectedAveragePercentage > 0) {
                    const rawGrade = (studentProductivityPercentage / expectedAveragePercentage) * 10;
                    const cappedGrade = Math.min(rawGrade, 10);
                    finalDisplayPercentage = (cappedGrade / 10) * 100;
                }
            }

            return {
                id,
                name: statData.name,
                completed: completedStats,
                inProgress: inProgressStats,
                pending: pendingStats,
                totalAssigned: totalStats,
                productivity: Math.round(finalDisplayPercentage),
            };
        });

        return result.sort((a, b) => b.totalAssigned.count - a.totalAssigned.count);
    }, [freshGroupMembers, tasks, project.id]);

    const difficultyConfig: { [key in Difficulty]: { bg: string, text: string, name: string } } = {
        [Difficulty.Level1]: { bg: 'bg-green-200', text: 'text-green-800', name: 'Sencilla' },
        [Difficulty.Level2]: { bg: 'bg-yellow-200', text: 'text-yellow-800', name: 'Moderada' },
        [Difficulty.Level3]: { bg: 'bg-red-200', text: 'text-red-800', name: 'Compleja' },
    };

    return (
        <div className="w-full p-4 bg-white rounded-lg shadow-md">
            <div onClick={() => onNavigateToKanban(project.id)} className="cursor-pointer">
                <div className="flex flex-col sm:flex-row items-stretch gap-6">
                    <div className="flex-shrink-0 flex items-center justify-center">
                        <ProgressCircle progress={progress} size={96} />
                    </div>
                    <div className="flex-1 min-w-0">
                        <h3 className="text-xl font-bold text-green-700">{project.name}</h3>
                        <p className="text-base text-gray-500">{user.courseGroup} - {group.name}</p>
                        {tutor && <p className="mt-1 text-sm italic font-bold text-green-800">Tutor/a: {tutor.name}</p>}
                        <div className="pt-2 mt-2 border-t border-gray-200">
                            <h4 className="mb-1 text-sm font-semibold text-gray-600">Componentes del Grupo:</h4>
                            <div className="flex flex-wrap gap-x-4 gap-y-1">
                                {freshGroupMembers
                                    .filter(member => member.role === Role.Student)
                                    .map(member => (
                                    <span key={member.id} className="text-sm text-gray-800">{member.name}</span>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2 pt-3 mt-3 border-t md:grid-cols-3 border-gray-200">
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Inicio de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.startDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <div className="text-center">
                        <p className="text-sm font-medium text-gray-500">Fin de Proyecto</p>
                        <p className="text-base font-bold text-gray-800">{new Date(project.endDate + 'T00:00:00').toLocaleDateString('es-ES')}</p>
                    </div>
                    <CountdownDisplay endDate={project.endDate} />
                </div>

                <div className="pt-3 mt-3 border-t border-gray-200">
                    <div className="grid grid-cols-2 gap-4 md:grid-cols-4">
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Reuniones de Grupo</p>
                            <p className="text-2xl font-bold text-blue-600">{groupMeetingsCount}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Reunión Grupo</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextGroupMeetingDate}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Tutorías Realizadas</p>
                            <p className="text-2xl font-bold text-blue-600">{pastTutorialsCount}</p>
                        </div>
                        <div className="p-2 text-center bg-gray-50 rounded-lg">
                            <p className="text-sm font-medium text-gray-500">Próxima Tutoría</p>
                            <p className="text-base font-bold text-blue-600 break-words">{nextTutorialDate}</p>
                        </div>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 pt-3 mt-3 border-t border-gray-200">
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-gray-800">{totalTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Tareas Totales</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-red-600">{pendingTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Pendientes</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-blue-600">{inProgressTasks}</p>
                    <p className="text-sm font-medium text-gray-500">En Curso</p>
                </div>
                <div className="p-3 text-center bg-gray-50 rounded-lg border border-gray-200">
                    <p className="text-2xl font-bold text-green-600">{completedTasks}</p>
                    <p className="text-sm font-medium text-gray-500">Completadas</p>
                </div>
            </div>

            <div className="pt-3 mt-3 border-t border-gray-200">
                <div className="flex flex-wrap items-center justify-between gap-2 mb-3">
                    <h4 className="text-lg font-bold text-gray-700">Rendimiento del Grupo por Tareas</h4>
                    <div className="flex items-center space-x-4">
                        <span className="text-xs font-semibold text-gray-500">Dificultad:</span>
                        {(Object.keys(difficultyConfig) as Difficulty[]).map(level => (
                            <div key={level} className="flex items-center space-x-1.5">
                                <div className={`w-3 h-3 rounded-full ${difficultyConfig[level].bg}`}></div>
                                <span className="text-xs text-gray-600">{difficultyConfig[level].name}</span>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="hidden md:flex mb-2">
                    <div className="w-full md:w-1/3" /> {/* Spacer */}
                    <div className="flex w-full md:w-2/3">
                        <div className="flex-1 text-center text-xs font-bold text-gray-500">Total</div>
                        <div className="flex-1 text-center text-xs font-bold text-red-600">Pendientes</div>
                        <div className="flex-1 text-center text-xs font-bold text-blue-600">En Progreso</div>
                        <div className="flex-1 text-center text-xs font-bold text-green-600">Realizadas</div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-2">
                    {memberStats.map(stat => {
                        const name = stat.name;
                        const firstSpaceIndex = name.indexOf(' ');
                        const firstName = firstSpaceIndex === -1 ? name : name.substring(0, firstSpaceIndex);
                        const lastName = firstSpaceIndex === -1 ? '' : name.substring(firstSpaceIndex + 1);

                        return (
                            <div key={stat.id} className="flex items-center p-2 bg-gray-50 rounded-lg border border-gray-200">
                                <div className="flex items-center w-1/3">
                                    <div className="flex-shrink-0" title={`Productividad: ${stat.productivity}%`}>
                                        <ProgressCircle progress={stat.productivity} size={40} />
                                    </div>
                                    <div className="ml-3 flex-1 min-w-0" title={stat.name}>
                                        <p className="font-medium text-gray-800 truncate">{firstName}</p>
                                        {lastName && <p className="text-sm text-gray-600 truncate">{lastName}</p>}
                                    </div>
                                </div>
                                <div className="flex justify-around w-2/3">
                                    <StatusColumn title="Total de Tareas" mainCircleClass="bg-black" stats={stat.totalAssigned} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Pendientes" mainCircleClass="bg-red-500" stats={stat.pending} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas En Progreso" mainCircleClass="bg-blue-600" stats={stat.inProgress} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Realizadas" mainCircleClass="bg-green-600" stats={stat.completed} difficultyConfig={difficultyConfig} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};


const StudentDashboard: React.FC<{
    user: User;
    groups: Group[];
    projects: Project[];
    tasks: Task[];
    tutorials: Tutorial[];
    allUsers: User[];
    onNavigateToKanban: (projectId: string) => void;
}> = ({ user, groups, projects, tasks, tutorials, allUsers, onNavigateToKanban }) => {

    const userProjectsWithGroups = useMemo(() => {
        return projects
            .filter(p => user.groupIds.includes(p.groupId))
            .map(project => ({
                project,
                group: groups.find(g => g.id === project.groupId)
            }))
            .filter((item): item is { project: Project; group: Group } => !!item.group);
    }, [user, projects, groups]);

    if (userProjectsWithGroups.length === 0) {
        return (
            <div className="p-6 text-center text-gray-500 bg-white rounded-lg shadow-md">
                <p>Actualmente no estás asignado a ningún proyecto.</p>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {userProjectsWithGroups.map(({ project, group }) => (
                <StudentProjectDetailCard
                    key={project.id}
                    group={group}
                    project={project}
                    tasks={tasks}
                    tutorials={tutorials}
                    allUsers={allUsers}
                    user={user}
                    onNavigateToKanban={onNavigateToKanban}
                />
            ))}
        </div>
    );
};

const AdminTutorDashboard: React.FC<{ 
    groups: Group[]; 
    projects: Project[]; 
    tasks: Task[]; 
    allUsers: User[]; 
    tutorials: Tutorial[];
    onNavigateToKanban: (projectId: string) => void; 
}> = ({ groups, projects, tasks, allUsers, tutorials, onNavigateToKanban }) => {
    const [expandedCourseGroups, setExpandedCourseGroups] = useState<Record<string, boolean>>({});

    const projectsByCourseGroup = useMemo(() => {
        const result: Record<string, { project: Project, group: Group }[]> = {};

        projects.forEach(project => {
            const group = groups.find(g => g.id === project.groupId);
            if (group && group.members.length > 0) {
                let projectCourseGroup: string | undefined;
                for (const member of group.members) {
                    const freshMember = allUsers.find(u => u.id === member.id);
                    if (freshMember && freshMember.courseGroup) {
                        projectCourseGroup = freshMember.courseGroup;
                        break;
                    }
                }

                if (projectCourseGroup) {
                    if (!result[projectCourseGroup]) {
                        result[projectCourseGroup] = [];
                    }
                    result[projectCourseGroup].push({ project, group });
                }
            }
        });
        return result;
    }, [projects, groups, allUsers]);

    const toggleCourseGroup = (courseGroupName: string) => {
        setExpandedCourseGroups(prev => ({ ...prev, [courseGroupName]: !prev[courseGroupName] }));
    };

    return (
        <div className="space-y-4">
            {Object.keys(projectsByCourseGroup).sort().map(courseGroup => {
                const projectsData = projectsByCourseGroup[courseGroup];
                const isExpanded = !!expandedCourseGroups[courseGroup];
                return (
                    <div key={courseGroup} className="bg-white rounded-lg shadow-md">
                        <button onClick={() => toggleCourseGroup(courseGroup)} className="flex items-center justify-between w-full p-4 text-left focus:outline-none">
                            <div className="flex items-center">
                                <h3 className="text-lg font-semibold text-gray-800">{courseGroup}</h3>
                                <span className="ml-4 px-3 py-1 text-sm font-semibold text-green-800 bg-green-100 rounded-full">{projectsData.length} {projectsData.length === 1 ? 'proyecto' : 'proyectos'}</span>
                            </div>
                            <ChevronDownIcon className={`w-6 h-6 text-gray-500 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </button>
                        {isExpanded && (
                            <div className="p-4 border-t border-gray-200">
                                <div className="grid grid-cols-1 gap-6">
                                    {projectsData.map(({ project, group }) => (
                                        <AdminTutorGroupCard
                                            key={project.id}
                                            group={group}
                                            project={project}
                                            tasks={tasks}
                                            allUsers={allUsers}
                                            tutorials={tutorials}
                                            onNavigateToKanban={onNavigateToKanban}
                                        />
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
};

const Dashboard: React.FC<DashboardProps> = ({ user, groups, projects, tasks, allUsers, messages, tutorials, onNavigateToKanban, onSendMessage, onMarkMessagesAsRead }) => {
    const [isPendingModalOpen, setIsPendingModalOpen] = useState(false);

    const unreadMessages = useMemo(() => messages.filter(msg => 
        msg.recipientIds.includes(user.id) && !msg.readBy.includes(user.id)
    ), [messages, user.id]);

    const handleClosePendingModal = () => {
        setIsPendingModalOpen(false);
    };

    const { visibleGroups, visibleProjects } = useMemo(() => {
        if (user.role === Role.Admin) {
            return { visibleGroups: groups, visibleProjects: projects };
        }
        if (user.role === Role.Tutor) {
            const tutorGroups = groups.filter(g => g.tutorId === user.id);
            const tutorGroupIds = tutorGroups.map(g => g.id);
            const tutorProjects = projects.filter(p => tutorGroupIds.includes(p.groupId));
            return { visibleGroups: tutorGroups, visibleProjects: tutorProjects };
        }
        return { visibleGroups: [], visibleProjects: [] };
    }, [user, groups, projects]);

    return (
        <div>
            <div className="flex flex-wrap items-center justify-between gap-4 mb-6">
                <h2 className="text-2xl font-bold text-gray-800">
                    {user.role === Role.Student ? 'Mis Proyectos' : 'Proyectos por Curso'}
                </h2>
                <button
                    onClick={() => unreadMessages.length > 0 && setIsPendingModalOpen(true)}
                    className={`px-4 py-2 font-bold rounded-md transition-all ${
                        unreadMessages.length > 0
                            ? 'bg-red-500 text-white blinking-button shadow-lg hover:bg-red-600'
                            : 'bg-green-500 text-white cursor-default'
                    }`}
                >
                    {unreadMessages.length > 0 ? `Mensajes Pendientes (${unreadMessages.length})` : 'Sin Mensajes Pendientes'}
                </button>
            </div>

            {(user.role === Role.Admin || user.role === Role.Tutor)
                ? <AdminTutorDashboard 
                    groups={visibleGroups} 
                    projects={visibleProjects} 
                    tasks={tasks} 
                    allUsers={allUsers} 
                    tutorials={tutorials}
                    onNavigateToKanban={onNavigateToKanban} 
                  /> 
                : <StudentDashboard 
                    user={user} 
                    groups={groups} 
                    projects={projects} 
                    tasks={tasks} 
                    tutorials={tutorials}
                    allUsers={allUsers}
                    onNavigateToKanban={onNavigateToKanban} 
                  />}

            {isPendingModalOpen && (
                <PendingMessagesModal
                    user={user}
                    messages={unreadMessages}
                    allUsers={allUsers}
                    onClose={handleClosePendingModal}
                    onSendMessage={onSendMessage}
                    onMarkMessagesAsRead={onMarkMessagesAsRead}
                />
            )}
        </div>
    );
};

export default Dashboard;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { User, Group, Task, Project, Role, RA, Tutorial, StoredFile, Message } from './types';
import { MOCK_USERS, MOCK_GROUPS, MOCK_TASKS, MOCK_PROJECTS, MOCK_RAS, MOCK_TUTORIALS, MOCK_FILES, MOCK_MESSAGES } from './data';
import LoginPage from './components/LoginPage';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import KanbanBoard from './components/KanbanBoard';
import GanttChart from './components/GanttChart';
import Groups from './components/Groups';
import Tutors from './components/Tutors';
import RAs from './components/RAs';
import Students from './components/Students';
import Files from './components/Files';
import Calendar from './components/Calendar';
import ProjectDates from './components/ProjectDates';
import Messaging from './components/Messaging';
import NotificationModal from './components/NotificationModal';
import InformationPage from './components/InformationPage';

export type Page = 'dashboard' | 'students' | 'ras' | 'tutors' | 'board' | 'gantt' | 'groups' | 'files' | 'calendar' | 'project-dates' | 'messaging' | 'information';

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [page, setPage] = useState<Page>('dashboard');
    const [selectedKanbanProject, setSelectedKanbanProject] = useState<string | null>(null);
    const [authError, setAuthError] = useState<string>('');
    const [unreadMessagesToShow, setUnreadMessagesToShow] = useState<Message[]>([]);

    // Centralized state for application data
    const [users, setUsers] = useState<User[]>(MOCK_USERS);
    const [groups, setGroups] = useState<Group[]>(MOCK_GROUPS);
    const [tasks, setTasks] = useState<Task[]>(MOCK_TASKS);
    const [projects, setProjects] = useState<Project[]>(MOCK_PROJECTS);
    const [ras, setRas] = useState<RA[]>(MOCK_RAS);
    const [tutorials, setTutorials] = useState<Tutorial[]>(MOCK_TUTORIALS);
    const [files, setFiles] = useState<StoredFile[]>(MOCK_FILES);
    const [messages, setMessages] = useState<Message[]>(MOCK_MESSAGES);
    const [courseDates, setCourseDates] = useState({ startDate: '2025-09-15', endDate: '2026-06-19' });

    const initialModules = useMemo(() => Array.from(new Set(MOCK_RAS.map(r => r.module))), []);
    const [modules, setModules] = useState<string[]>(initialModules);


    const handleLogin = useCallback((username: string, password: string): void => {
        const user = users.find(u => u.username.toLowerCase() === username.toLowerCase() && u.password === password);
        if (user) {
            setCurrentUser(user);
            setAuthError('');
            setPage('dashboard');

            const unread = messages.filter(msg => 
                msg.recipientIds.includes(user.id) && !msg.readBy.includes(user.id)
            );
            if (unread.length > 0) {
                setUnreadMessagesToShow(unread);
            }

        } else {
            setAuthError('Usuario o contraseña incorrectos.');
        }
    }, [users, messages]);

    const handleLogout = useCallback((): void => {
        setCurrentUser(null);
    }, []);

    const handleSendMessage = (messageData: { senderId: string; recipientIds: string[]; subject: string; body: string; targetType: 'tutors' | 'groups' | 'students'; targetGroupIds?: string[]; originalMessageId?: string; }) => {
        const newMessage: Message = {
            id: `msg-${Date.now()}`,
            ...messageData,
            timestamp: new Date().toISOString(),
            readBy: [],
        };

        if (messageData.originalMessageId) {
            // This is a reply, update the original message
            setMessages(prev => {
                const originalMessage = prev.find(m => m.id === messageData.originalMessageId);
                if (originalMessage) {
                    const updatedOriginalMessage = { ...originalMessage, repliedBy: messageData.senderId };
                    return [...prev.filter(m => m.id !== messageData.originalMessageId), updatedOriginalMessage, newMessage];
                }
                return [...prev, newMessage]; // Fallback if original not found
            });
        } else {
             setMessages(prev => [...prev, newMessage]);
        }
    };

    const handleMarkMessagesAsRead = (messageIds: string[]) => {
        if (!currentUser) return;
        setMessages(prev =>
            prev.map(msg =>
                messageIds.includes(msg.id) && !msg.readBy.includes(currentUser.id)
                    ? { ...msg, readBy: [...msg.readBy, currentUser.id] }
                    : msg
            )
        );
         setUnreadMessagesToShow(prev => prev.filter(msg => !messageIds.includes(msg.id)));
    };

    const handleDeleteMessage = (messageId: string) => {
        setMessages(prev => prev.filter(msg => msg.id !== messageId));
    };

    const handleCreateGroup = (groupData: { name: string; tutorId: string; memberIds: string[]; projectName: string; projectDescription: string; startDate: string; endDate: string; }) => {
        const groupId = `group-${Date.now()}`;
        const newGroup: Group = {
            id: groupId,
            name: groupData.name,
            tutorId: groupData.tutorId,
            members: users.filter(u => groupData.memberIds.includes(u.id)),
        };
         const newProject: Project = {
            id: `proj-${Date.now()}`,
            name: groupData.projectName,
            description: groupData.projectDescription,
            groupId: groupId,
            startDate: groupData.startDate,
            endDate: groupData.endDate,
        };
        setGroups(prevGroups => [...prevGroups, newGroup]);
        setProjects(prevProjects => [...prevProjects, newProject]);
    };

    const handleUpdateGroup = (groupId: string, groupData: { name: string; tutorId: string; memberIds: string[]; projectName: string; projectDescription: string; startDate: string; endDate: string; }) => {
        setGroups(prevGroups =>
            prevGroups.map(group =>
                group.id === groupId
                    ? {
                          ...group,
                          name: groupData.name,
                          tutorId: groupData.tutorId,
                          members: users.filter(u => groupData.memberIds.includes(u.id)),
                      }
                    : group
            )
        );
         setProjects(prevProjects => 
            prevProjects.map(project => 
                project.groupId === groupId 
                    ? {
                        ...project,
                        name: groupData.projectName,
                        description: groupData.projectDescription,
                        startDate: groupData.startDate,
                        endDate: groupData.endDate,
                      }
                    : project
            )
        );
    };

    const handleDeleteGroup = (groupId: string) => {
        const projectsToDelete = projects.filter(p => p.groupId === groupId);
        const projectIdsToDelete = projectsToDelete.map(p => p.id);
        setTasks(prevTasks => prevTasks.filter(t => !projectIdsToDelete.includes(t.projectId)));
        setProjects(prevProjects => prevProjects.filter(p => p.groupId !== groupId));
        setGroups(prevGroups => prevGroups.filter(group => group.id !== groupId));
    };

    const handleCreateTutor = (tutorData: { name: string; password?: string }) => {
        const newTutor: User = {
            id: `user-${Date.now()}`,
            name: tutorData.name,
            username: tutorData.name.split(' ')[0].toLowerCase() + Date.now().toString().slice(-4),
            password: tutorData.password || 'password',
            role: Role.Tutor,
            groupIds: [],
        };
        setUsers(prevUsers => [...prevUsers, newTutor]);
    };

    const handleUpdateTutor = (tutorId: string, tutorData: { name: string; password?: string }) => {
        setUsers(prevUsers =>
            prevUsers.map(user =>
                user.id === tutorId
                    ? {
                          ...user,
                          name: tutorData.name,
                          ...(tutorData.password && { password: tutorData.password }),
                      }
                    : user
            )
        );
    };

    const handleDeleteTutor = (tutorId: string) => {
        setGroups(prevGroups =>
            prevGroups.map(group =>
                group.tutorId === tutorId
                    ? { ...group, tutorId: '' }
                    : group
            )
        );
        setUsers(prevUsers => prevUsers.filter(user => user.id !== tutorId));
    };

    const handleCreateStudent = (studentData: { name: string; password?: string; courseGroup: string }) => {
        const newStudent: User = {
            id: `user-${Date.now()}`,
            name: studentData.name,
            username: studentData.name.split(' ')[0].toLowerCase() + Date.now().toString().slice(-4),
            password: studentData.password || 'password',
            role: Role.Student,
            groupIds: [], // Initially not assigned to a project group
            courseGroup: studentData.courseGroup,
        };
        setUsers(prevUsers => [...prevUsers, newStudent]);
    };

    const handleCreateStudentsBulk = (studentsData: { name: string; password: string; courseGroup: string }[]) => {
        const timestamp = Date.now();
        const newStudents: User[] = studentsData.map((studentData, index) => ({
            id: `user-${timestamp}-${index}`,
            name: studentData.name.trim(),
            username: studentData.name.trim().split(' ')[0].toLowerCase() + timestamp.toString().slice(-4) + index,
            password: studentData.password.trim(),
            role: Role.Student,
            groupIds: [],
            courseGroup: studentData.courseGroup,
        }));
        setUsers(prevUsers => [...prevUsers, ...newStudents]);
    };

    const handleUpdateStudent = (studentId: string, studentData: { name: string; password?: string; courseGroup: string }) => {
        setUsers(prevUsers =>
            prevUsers.map(user =>
                user.id === studentId
                    ? {
                          ...user,
                          name: studentData.name,
                          courseGroup: studentData.courseGroup,
                          ...(studentData.password && { password: studentData.password }),
                      }
                    : user
            )
        );
    };

    const handleDeleteStudent = (studentId: string) => {
        setGroups(prevGroups => 
            prevGroups.map(g => ({ ...g, members: g.members.filter(m => m.id !== studentId) }))
        );
        setTasks(prevTasks =>
            prevTasks.map(t => t.assigneeId === studentId ? { ...t, assigneeId: ''} : t)
        )
        setUsers(prevUsers => prevUsers.filter(user => user.id !== studentId));
    };


    const handleCreateTask = (taskData: Omit<Task, 'id'>) => {
        const newTask: Task = {
            id: `task-${Date.now()}`,
            ...taskData,
        };
        setTasks(prevTasks => [...prevTasks, newTask]);
    };

    const handleUpdateTask = (taskId: string, taskData: Partial<Omit<Task, 'id'>>) => {
        setTasks(prevTasks =>
            prevTasks.map(task =>
                task.id === taskId ? { ...task, ...taskData } : task
            )
        );
    };

    const handleDeleteTask = (taskId: string) => {
        setTasks(prevTasks => prevTasks.filter(task => task.id !== taskId));
    };

    const handleCreateRA = (raData: { module: string; code: string; description: string }) => {
        const newRA: RA = {
            id: `ra-${Date.now()}`,
            ...raData,
        };
        setRas(prevRas => [...prevRas, newRA]);
    };

    const handleUpdateRA = (raId: string, raData: { module: string; code: string; description: string }) => {
        setRas(prevRas =>
            prevRas.map(ra =>
                ra.id === raId ? { ...ra, ...raData } : ra
            )
        );
    };

    const handleDeleteRA = (raId: string) => {
        setTasks(prevTasks =>
            prevTasks.map(task =>
                task.raId === raId ? { ...task, raId: '' } : task
            )
        );
        setRas(prevRas => prevRas.filter(ra => ra.id !== raId));
    };

    const handleCreateModule = (moduleName: string) => {
        const trimmedName = moduleName.trim();
        if (trimmedName && !modules.some(m => m.trim().toLowerCase() === trimmedName.toLowerCase())) {
            setModules(prev => [...prev, trimmedName].sort());
        }
    };

    const handleUpdateModule = (oldName: string, newName: string) => {
        setModules(prev => prev.map(m => (m === oldName ? newName : m)).sort());
        setRas(prevRas => prevRas.map(ra => (ra.module === oldName ? { ...ra, module: newName } : ra)));
    };

    const handleDeleteModule = (moduleName: string) => {
        const raIdsToDelete = ras.filter(ra => ra.module === moduleName).map(r => r.id);
        setTasks(prevTasks =>
            prevTasks.map(task =>
                raIdsToDelete.includes(task.raId) ? { ...task, raId: '' } : task
            )
        );
        setRas(prevRas => prevRas.filter(ra => ra.module !== moduleName));
        setModules(prev => prev.filter(m => m !== moduleName));
    };

    const handleCreateTutorial = (tutorialData: Omit<Tutorial, 'id'>) => {
        const newTutorial: Tutorial = {
            id: `tut-${Date.now()}`,
            ...tutorialData,
        };
        setTutorials(prevTutorials => [...prevTutorials, newTutorial]);
    };

    const handleUpdateTutorial = (tutorialId: string, tutorialData: Partial<Omit<Tutorial, 'id'>>) => {
        setTutorials(prev => prev.map(t => t.id === tutorialId ? { ...t, ...tutorialData } : t));
    };

    const handleDeleteTutorial = (tutorialId: string) => {
        setTutorials(prev => prev.filter(t => t.id !== tutorialId));
    };

    const handleUpdateCourseDates = (dates: { startDate: string, endDate: string }) => {
        setCourseDates(dates);
    };

    const handleUploadFile = (file: File, groupId: string) => {
        const newFile: StoredFile = {
            id: `file-${Date.now()}`,
            name: file.name,
            url: '#', // Placeholder URL for mock data
            uploadedAt: new Date().toISOString(),
            groupId: groupId,
        };
        setFiles(prevFiles => [...prevFiles, newFile]);
    };

    const handleDeleteFile = (fileId: string) => {
        setFiles(prevFiles => prevFiles.filter(file => file.id !== fileId));
    };

    const handleNavigateToKanban = (projectId: string) => {
        setPage('board');
        setSelectedKanbanProject(projectId);
    };

    const renderPage = useMemo(() => {
        if (!currentUser) return null;
        switch (page) {
            case 'dashboard':
                return <Dashboard 
                            user={currentUser} 
                            groups={groups} 
                            projects={projects} 
                            tasks={tasks} 
                            allUsers={users}
                            messages={messages}
                            tutorials={tutorials}
                            onNavigateToKanban={handleNavigateToKanban}
                            onSendMessage={handleSendMessage}
                            onMarkMessagesAsRead={handleMarkMessagesAsRead}
                        />;
            case 'project-dates':
                return <ProjectDates
                            courseDates={courseDates}
                            onUpdate={handleUpdateCourseDates}
                        />;
            case 'students':
                return <Students 
                            users={users}
                            onCreate={handleCreateStudent}
                            onCreateBulk={handleCreateStudentsBulk}
                            onUpdate={handleUpdateStudent}
                            onDelete={handleDeleteStudent}
                        />;
            case 'ras':
                return <RAs
                            ras={ras}
                            modules={modules}
                            onCreateRA={handleCreateRA}
                            onUpdateRA={handleUpdateRA}
                            onDeleteRA={handleDeleteRA}
                            onCreateModule={handleCreateModule}
                            onUpdateModule={handleUpdateModule}
                            onDeleteModule={handleDeleteModule}
                        />;
            case 'tutors':
                return <Tutors 
                            users={users}
                            groups={groups}
                            onCreate={handleCreateTutor}
                            onUpdate={handleUpdateTutor}
                            onDelete={handleDeleteTutor}
                        />;
            case 'board':
                return <KanbanBoard 
                            user={currentUser} 
                            groups={groups} 
                            projects={projects} 
                            tasks={tasks}
                            users={users}
                            ras={ras}
                            courseDates={courseDates}
                            onCreateTask={handleCreateTask}
                            onUpdateTask={handleUpdateTask}
                            onDeleteTask={handleDeleteTask}
                            initialProjectId={selectedKanbanProject}
                            onProjectSelected={() => setSelectedKanbanProject(null)}
                        />;
            case 'gantt':
                return <GanttChart 
                            user={currentUser} 
                            groups={groups} 
                            projects={projects} 
                            tasks={tasks} 
                            courseDates={courseDates} 
                            allUsers={users} 
                            ras={ras}
                            onUpdateTask={handleUpdateTask}
                            onDeleteTask={handleDeleteTask}
                        />;
            case 'groups':
                return <Groups 
                            user={currentUser} 
                            groups={groups} 
                            projects={projects}
                            allUsers={users}
                            tasks={tasks}
                            courseDates={courseDates}
                            onCreate={handleCreateGroup}
                            onUpdate={handleUpdateGroup}
                            onDelete={handleDeleteGroup}
                            onNavigateToKanban={handleNavigateToKanban}
                        />;
            case 'messaging':
                return <Messaging 
                            user={currentUser}
                            allUsers={users}
                            groups={groups}
                            projects={projects}
                            messages={messages}
                            onSendMessage={handleSendMessage}
                            onDeleteMessage={handleDeleteMessage}
                            onMarkMessagesAsRead={handleMarkMessagesAsRead}
                        />;
            case 'files':
                return <Files 
                            user={currentUser}
                            files={files}
                            groups={groups}
                            allUsers={users}
                            projects={projects}
                            onUploadFile={handleUploadFile}
                            onDeleteFile={handleDeleteFile}
                        />;
            case 'calendar':
                return <Calendar 
                            user={currentUser}
                            tutorials={tutorials}
                            groups={groups}
                            allUsers={users}
                            projects={projects}
                            onCreateTutorial={handleCreateTutorial}
                            onUpdateTutorial={handleUpdateTutorial}
                            onDeleteTutorial={handleDeleteTutorial}
                            courseDates={courseDates}
                        />;
            case 'information':
                return <InformationPage />;
            default:
                 return <Dashboard 
                            user={currentUser} 
                            groups={groups} 
                            projects={projects} 
                            tasks={tasks} 
                            allUsers={users}
                            messages={messages}
                            tutorials={tutorials}
                            onNavigateToKanban={handleNavigateToKanban}
                            onSendMessage={handleSendMessage}
                            onMarkMessagesAsRead={handleMarkMessagesAsRead}
                        />;
        }
    }, [page, currentUser, users, groups, projects, tasks, ras, modules, tutorials, files, courseDates, selectedKanbanProject, messages]);

    if (!currentUser) {
        return <LoginPage onLogin={handleLogin} error={authError} />;
    }

    return (
        <Layout user={currentUser} onLogout={handleLogout} currentPage={page} setPage={setPage}>
            {renderPage}
            {unreadMessagesToShow.length > 0 && currentUser && (
                <NotificationModal
                    messages={unreadMessagesToShow}
                    allUsers={users}
                    onClose={() => {
                        setUnreadMessagesToShow([]);
                    }}
                    onReply={() => {
                        setPage('messaging');
                        setUnreadMessagesToShow([]);
                    }}
                    onMarkMessagesAsRead={handleMarkMessagesAsRead}
                />
            )}
        </Layout>
    );
};

export default App;

