import React from 'react';
import { Task, RA, KanbanStatus, User } from '../types';
import { PRIORITY_COLORS, STATUS_BADGE_COLORS } from '../constants';

interface KanbanCardProps {
    task: Task;
    ras: RA[];
    users: User[];
    onClick: () => void;
    viewMode: 'status' | 'priority';
}

const formatDate = (dateStr: string): string => {
    if (!dateStr) return '';
    const [year, month, day] = dateStr.split('-');
    const shortYear = year.slice(-2);
    return `${day}/${month}/${shortYear}`;
};

const KanbanCard: React.FC<KanbanCardProps> = ({ task, ras, users, onClick, viewMode }) => {
    const assignee = users.find(user => user.id === task.assigneeId);
    const ra = ras.find(r => r.id === task.raId);

    const getDateColor = (): string => {
        if (task.status === KanbanStatus.Done) {
            return 'text-gray-400';
        }
        const today = new Date();
        today.setHours(0, 0, 0, 0); 
        const endDate = new Date(task.endDate);

        if (endDate < today) {
            return 'text-red-500 font-bold'; 
        }
        return 'text-green-600';
    };

    const dateColorClass = getDateColor();

    return (
        <div onClick={onClick} className="p-3 bg-white rounded-lg shadow-sm cursor-pointer hover:shadow-md transition-shadow">
            <div className="flex items-start justify-between">
                <h4 className="mb-2 font-semibold text-gray-800">{task.title}</h4>
                {viewMode === 'status' ? (
                    <div className={`px-2 py-0.5 text-xs font-medium border rounded-full ${PRIORITY_COLORS[task.priority]}`}>
                        {task.priority}
                    </div>
                ) : (
                    <div className={`px-2 py-0.5 text-xs font-medium border rounded-full ${STATUS_BADGE_COLORS[task.status]}`}>
                        {task.status}
                    </div>
                )}
            </div>
            <p className="mb-3 text-sm text-gray-600">{task.description}</p>

            {ra && (
                <div className="p-1.5 mb-3 text-xs text-gray-700 bg-gray-100 border border-gray-200 rounded-md">
                    <span className="font-semibold">{ra.module} / {ra.code}:</span> {ra.description}
                </div>
            )}

            <div className="flex items-center justify-between pt-2 border-t border-gray-200">
                {assignee ? (
                    <div className="flex items-center">
                         <span className="text-xs font-medium text-gray-600">
                             <span className="font-semibold">Responsable: </span>
                             {assignee.name}
                         </span>
                    </div>
                ) : <div/>}
                <div className={`text-xs ${dateColorClass}`}>
                    {`${formatDate(task.startDate)} - ${formatDate(task.endDate)}`}
                </div>
            </div>
        </div>
    );
};

