                pending: calculateTaskStats(pendingTasks),
                totalAssigned: calculateTaskStats(statData.tasks),
                productivity: Math.round(productivity),
                assignedPoints: pa,
                achievedPoints: pl,
            };
        });

        return result.sort((a, b) => b.totalAssigned.count - a.totalAssigned.count);
