                                    <StatusColumn title="Tareas Pendientes" mainCircleClass="bg-red-500" stats={stat.pending} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas En Progreso" mainCircleClass="bg-blue-600" stats={stat.inProgress} difficultyConfig={difficultyConfig} />
                                    <StatusColumn title="Tareas Realizadas" mainCircleClass="bg-green-600" stats={stat.completed} difficultyConfig={difficultyConfig} />
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};


