const CountdownDisplay: React.FC<{ endDate: string }> = ({ endDate }) => {
    const timeLeft = useMemo(() => {
        const parts = endDate.split('-').map(Number);
        if (parts.length !== 3 || parts.some(isNaN)) {
            return { overdue: true, weeks: 0, days: 0 };
        }

        const today = new Date();

        // Construct dates as UTC to avoid timezone shifts during calculation.
        const todayUTC = Date.UTC(today.getFullYear(), today.getMonth(), today.getDate());
        const endDateUTC = Date.UTC(parts[0], parts[1] - 1, parts[2]);

        if (endDateUTC < todayUTC) {
             return { overdue: true, weeks: 0, days: 0 };
        }

        const oneDay = 1000 * 60 * 60 * 24;

        const totalDays = Math.floor((endDateUTC - todayUTC) / oneDay) + 1;

        if (totalDays <= 0) {
             return { overdue: true, weeks: 0, days: 0 };
        }

        const weeks = Math.floor(totalDays / 7);
        const days = totalDays % 7;

        return { overdue: false, weeks, days };
    }, [endDate]);

    if (timeLeft.overdue) {
        return (
            <div className="text-center">
                <p className="text-sm font-bold text-red-600">Finalizado</p>
                <p className="text-xs font-medium text-gray-500">Estado</p>
            </div>
        );
    }
    return (
        <div className="text-center">
             <p className="text-sm font-bold text-yellow-600">{`${timeLeft.weeks}sem ${timeLeft.days}d`}</p>
             <p className="text-xs font-medium text-gray-500">Restante</p>
        </div>
    );
};

const ProgressCircle: React.FC<{ progress: number; size?: number }> = ({ progress, size = 64 }) => {
